SET NAMES utf8mb4;

UPDATE document_templates SET faqs = '[{"q":"What should a professional invoice include to meet international standards?","a":"A compliant invoice should show a unique invoice number, issue date and due date, the full legal name and address of both the supplier and the customer, a clear description of goods or services with quantities and unit prices, the applicable tax (VAT/GST/sales tax) and tax registration numbers where required, the total amount due, the currency, and accepted payment methods. Invoxaco captures all of these and pulls your tax and bank details from your company profile automatically."},{"q":"Can I charge tax (VAT/GST/sales tax) and multiple currencies?","a":"Yes. You can set a tax rate for the whole invoice or per line item, add discounts and shipping, and choose the billing currency. The totals, subtotal and tax are calculated automatically."},{"q":"Can I download this Invoice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Invoice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'invoice-generator';
UPDATE document_templates SET faqs = '[{"q":"Is a receipt legally valid proof of payment?","a":"Yes. A receipt that identifies the payer and payee, the amount and currency, the date, what was paid for and the payment method is accepted internationally as proof that payment was received. Invoxaco records each of these fields."},{"q":"What is the difference between an invoice and a receipt?","a":"An invoice is a request for payment issued before payment; a receipt confirms that payment has already been received. Use the Invoice Generator to bill a customer and the Receipt Generator to acknowledge their payment."},{"q":"Can I download this Receipt as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Receipt suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'receipt-generator';
UPDATE document_templates SET faqs = '[{"q":"When should I issue a credit note?","a":"Issue a credit note when you need to reduce or cancel a previously issued invoice — for example after a return, an overcharge, a discount agreed after invoicing, or a billing error. It creates an auditable record that reverses part or all of the original invoice."},{"q":"Should a credit note reference the original invoice?","a":"Yes. Best practice (and a requirement under most VAT/GST regimes) is to reference the original invoice number and date so the adjustment is traceable. Enter the original invoice reference in the notes or reference field."},{"q":"Can I download this Credit Note as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Credit Note suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'credit-note-generator';
UPDATE document_templates SET faqs = '[{"q":"What is a debit note used for?","a":"A debit note is issued to increase the amount a customer owes, or by a buyer to a supplier to request a credit — for example for undercharged items, additional goods delivered, or returned purchases. It documents the adjustment for both parties'' records."},{"q":"How is a debit note different from an invoice?","a":"An invoice bills for an original sale; a debit note adjusts or supplements an existing transaction. It should reference the related invoice so the change is auditable."},{"q":"Can I download this Debit Note as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Debit Note suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'debit-note-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"report_title","label":"Report Title","type":"text","required":true,"default":"Expense Report"},{"name":"employee_name","label":"Employee / Claimant Name","type":"text","required":true},{"name":"employee_id","label":"Employee ID","type":"text","required":false},{"name":"department","label":"Department","type":"text","required":false},{"name":"manager_name","label":"Approving Manager","type":"text","required":false},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"items","label":"Expense Items","type":"line_items","required":true,"has_unit":true,"per_item_tax":true},{"name":"advance_received","label":"Advance / Float Received","type":"number","required":false},{"name":"purpose","label":"Business Purpose","type":"textarea","required":false,"default":"Expenses incurred in the course of authorized business activities on behalf of the company."},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Original receipts are attached for each line item in accordance with company expense policy."},{"name":"submitted_by_name","label":"Submitted By","type":"text","required":false},{"name":"submitted_by_signature","label":"Claimant Signature","type":"signature","required":false},{"name":"approved_by_name","label":"Approved By","type":"text","required":false},{"name":"approved_by_signature","label":"Approver Signature","type":"signature","required":false}]}', faqs = '[{"q":"What makes an expense report audit-ready?","a":"An audit-ready expense report itemises each expense with its date, category, amount and business purpose, references attached receipts, shows any advance or float received, and carries both the claimant''s and an approver''s sign-off. Invoxaco structures all of these so the report stands up to internal and tax audits."},{"q":"Can employees submit expenses in different currencies?","a":"Yes. Set the report currency and enter each line item accordingly. For multi-currency travel, convert to your reporting currency and note the rate used in the notes field."},{"q":"Can I download this Expense Report as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Expense Report suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'expense-report-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Profit & Loss Statement"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"revenue_items","label":"Revenue","type":"line_items","required":true},{"name":"cogs_items","label":"Cost of Goods Sold","type":"line_items","required":true},{"name":"operating_expenses","label":"Operating Expenses","type":"line_items","required":true},{"name":"other_items","label":"Other Income / (Expenses)","type":"line_items","required":true},{"name":"tax_expense","label":"Income Tax Expense","type":"number","required":false},{"name":"notes","label":"Notes to the Statement","type":"textarea","required":false,"default":"Figures are prepared on an accruals basis and are unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What does a profit and loss statement show?","a":"A profit and loss (income) statement summarises revenue, cost of goods sold, gross profit, operating expenses, and net profit or loss over a defined period. It is one of the three core financial statements used internationally to assess a business''s performance."},{"q":"Is this statement prepared under IFRS or US GAAP?","a":"The template uses a neutral, widely accepted income-statement structure compatible with both IFRS and US GAAP presentation. For statutory filing or audit, have your accountant confirm the presentation required in your jurisdiction."},{"q":"Can I download this Profit & Loss Statement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Profit & Loss Statement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'profit-and-loss-statement-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Balance Sheet"},{"name":"as_of_date","label":"As of Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"current_assets","label":"Current Assets","type":"line_items","required":true},{"name":"non_current_assets","label":"Non-Current Assets","type":"line_items","required":true},{"name":"current_liabilities","label":"Current Liabilities","type":"line_items","required":true},{"name":"non_current_liabilities","label":"Non-Current Liabilities","type":"line_items","required":true},{"name":"equity","label":"Equity","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"This statement of financial position is prepared on a going-concern basis and is unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is a balance sheet and what must balance?","a":"A balance sheet (statement of financial position) lists a company''s assets, liabilities and equity at a point in time. It must always balance to the accounting equation: total assets = total liabilities + equity."},{"q":"Does this follow international presentation standards?","a":"Yes. The template groups items into current and non-current assets and liabilities plus equity, the structure used under both IFRS and US GAAP. Confirm any statutory note disclosures with your accountant for filing."},{"q":"Can I download this Balance Sheet as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Balance Sheet suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'balance-sheet-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Cash Flow Statement"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"opening_balance","label":"Opening Cash Balance","type":"number","required":true},{"name":"operating_activities","label":"Cash Flows from Operating Activities","type":"line_items","required":true},{"name":"investing_activities","label":"Cash Flows from Investing Activities","type":"line_items","required":true},{"name":"financing_activities","label":"Cash Flows from Financing Activities","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Prepared using the direct/indirect method as indicated; figures are unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What are the three sections of a cash flow statement?","a":"A cash flow statement is divided into operating activities (cash from core business), investing activities (purchase/sale of assets and investments), and financing activities (debt, equity and dividends). Together they reconcile opening and closing cash balances."},{"q":"Why is a cash flow statement important?","a":"Profit is not the same as cash. A cash flow statement shows whether a business is actually generating cash to meet its obligations, and is reviewed internationally by lenders, investors and auditors alongside the income statement and balance sheet."},{"q":"Can I download this Cash Flow Statement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Cash Flow Statement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'cash-flow-statement-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"organization_name","label":"Organization / Department","type":"text","required":true},{"name":"proposal_title","label":"Proposal Title","type":"text","required":true,"default":"Budget Proposal"},{"name":"prepared_for","label":"Prepared For","type":"text","required":false},{"name":"budget_period_from","label":"Budget Period From","type":"date","required":true},{"name":"budget_period_to","label":"Budget Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"objective","label":"Objective / Background","type":"textarea","required":false,"default":"This proposal sets out the estimated funding required to achieve the stated objectives for the budget period, with assumptions and justifications for each line."},{"name":"budget_items","label":"Budgeted Line Items","type":"line_items","required":true,"has_unit":true},{"name":"contingency_percent","label":"Contingency (%)","type":"number","required":false},{"name":"assumptions","label":"Key Assumptions","type":"textarea","required":false,"default":"Estimates are based on current pricing and prior-period actuals; material assumptions are noted against the relevant line items."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"approved_by_signature","label":"Approver Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a strong budget proposal contain?","a":"A persuasive budget proposal states the objective, defines the budget period, itemises each cost with quantities and unit prices, adds a contingency, and documents the assumptions behind the numbers — all signed off by a preparer and an approver. This structure is expected by finance committees and grant funders internationally."},{"q":"Can I include a contingency and justify each cost?","a":"Yes. Add a contingency percentage and use the assumptions field to justify estimates. Clear justification significantly improves approval rates for departmental and project budgets."},{"q":"Can I download this Budget Proposal as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Budget Proposal suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'budget-proposal-generator';
UPDATE document_templates SET faqs = '[{"q":"What should a payment receipt confirm?","a":"It should confirm the amount received, the currency, the date of payment, the payment method (cash, card, bank transfer, cheque), what the payment was for, and any remaining balance. This gives both parties a clear record for accounting and tax."},{"q":"Can I issue a receipt for a partial payment?","a":"Yes. Record the amount received and note the outstanding balance so both you and your customer have an accurate running record of the account."},{"q":"Can I download this Payment Receipt as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Payment Receipt suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'payment-receipt-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"statement_title","label":"Statement Title","type":"text","required":true,"default":"Financial Statement"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"income_items","label":"Income","type":"line_items","required":true},{"name":"expense_items","label":"Expenses","type":"line_items","required":true},{"name":"assets_items","label":"Assets","type":"line_items","required":true},{"name":"liabilities_items","label":"Liabilities","type":"line_items","required":true},{"name":"notes","label":"Notes / Basis of Preparation","type":"textarea","required":false,"default":"These financial statements are prepared on an accruals basis using consistent accounting policies and are unaudited unless otherwise stated."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is included in a set of financial statements?","a":"A complete set of financial statements typically includes an income statement, a statement of financial position (balance sheet), a cash flow statement and explanatory notes. This generator produces a consolidated summary suitable for management reporting, lenders and investors."},{"q":"Are these statements suitable for statutory filing?","a":"They provide a clear, internationally structured summary for management and stakeholders. For statutory or regulatory filing, have a qualified accountant prepare or review the statements to the exact standard (IFRS, US GAAP or local GAAP) required."},{"q":"Can I download this Financial Statement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Financial Statement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'financial-statement-generator';
UPDATE document_templates SET faqs = '[{"q":"Is a purchase order a legally binding document?","a":"Once a supplier accepts a purchase order it generally forms a binding contract for the goods or services, quantities, prices and terms stated on it. A clear PO number, delivery date and agreed terms make it enforceable and are standard practice for procurement worldwide."},{"q":"What should every purchase order include?","a":"A unique PO number, the buyer and supplier details, an itemised list with quantities and agreed unit prices, the delivery address and date, payment terms, and any tax. Invoxaco captures all of these and lets you reuse them across orders."},{"q":"Can I download this Purchase Order as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Purchase Order suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'purchase-order-generator';
UPDATE document_templates SET faqs = '[{"q":"What is the purpose of a sales order?","a":"A sales order confirms a seller''s acceptance of a customer''s order and records exactly what will be supplied, at what price, and on what delivery and payment terms. It is the seller''s internal and customer-facing record that turns a quote or PO into a committed sale."},{"q":"How does a sales order relate to an invoice?","a":"The sales order confirms the order details; the invoice later requests payment for the goods or services delivered against it. Keeping the same reference on both keeps your order-to-cash records consistent."},{"q":"Can I download this Sales Order as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Sales Order suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'sales-order-generator';
UPDATE document_templates SET faqs = '[{"q":"What is a proforma invoice and when is it used?","a":"A proforma invoice is a preliminary bill of sale sent before goods or services are supplied, commonly used for quotations, advance-payment requests, and customs/import declarations in international trade. It states the expected price and terms but is not a demand for payment."},{"q":"Is a proforma invoice the same as a commercial invoice?","a":"No. A proforma is issued before the transaction is finalised and is not booked as a receivable; a commercial (tax) invoice is issued once the sale is confirmed and is the document used for accounting and tax."},{"q":"Can I download this Proforma Invoice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Proforma Invoice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'proforma-invoice-generator';
UPDATE document_templates SET faqs = '[{"q":"What is a delivery note used for?","a":"A delivery note (or dispatch/packing note) accompanies a shipment and lists the goods being delivered so the recipient can check them against their order. A signed delivery note is widely accepted proof that goods were received in good condition."},{"q":"Should the customer sign the delivery note?","a":"Yes. Having the recipient sign confirms delivery and condition of the goods, which protects both parties in the event of a later dispute about what was delivered."},{"q":"Can I download this Delivery Note as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Delivery Note suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'delivery-note-generator';
UPDATE document_templates SET faqs = '[{"q":"What makes a sales proposal effective?","a":"An effective sales proposal clearly states the client''s need, your proposed solution, an itemised price, the deliverables and timeline, and a call to action. A professional, branded layout materially improves win rates."},{"q":"Can I convert an accepted proposal into an order or invoice?","a":"Yes. Reuse the same line items and client details to generate a matching sales order or invoice once the proposal is accepted, keeping your records consistent end-to-end."},{"q":"Can I download this Sales Proposal as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Sales Proposal suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'sales-proposal-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Your Company","type":"text","required":true},{"name":"document_title","label":"Document Title","type":"text","required":true,"default":"Price Quote Comparison"},{"name":"prepared_for","label":"Prepared For","type":"text","required":false},{"name":"comparison_date","label":"Date","type":"date","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"requirement","label":"Requirement / Scope","type":"textarea","required":false,"default":"This comparison evaluates supplier quotations received for the stated requirement on a like-for-like basis to support a transparent procurement decision."},{"name":"vendor_quotes","label":"Vendor Quotes","type":"line_items","required":true,"has_unit":true},{"name":"evaluation_criteria","label":"Evaluation Criteria","type":"textarea","required":false,"default":"Quotes are assessed on price, specification compliance, lead time, warranty, after-sales support and supplier track record."},{"name":"recommendation","label":"Recommendation","type":"textarea","required":false,"default":"Based on the evaluation criteria above, the recommended supplier offers the best overall value for the requirement."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_by_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"Why use a price quote comparison?","a":"A structured comparison documents that competing quotations were evaluated on a fair, like-for-like basis — price, specification, lead time, warranty and support — which is best practice for procurement and is often required for audit or grant compliance."},{"q":"Can I compare more than two suppliers?","a":"Yes. Add a line for each supplier''s quote and use the evaluation and recommendation fields to record why the chosen supplier offers the best overall value, not simply the lowest price."},{"q":"Can I download this Price Quote Comparison as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Price Quote Comparison suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'price-quote-comparison-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"business_name","label":"Business Name","type":"text","required":true},{"name":"voucher_title","label":"Voucher Title","type":"text","required":true,"default":"Discount Voucher"},{"name":"voucher_code","label":"Voucher Code","type":"text","required":true},{"name":"discount_type","label":"Discount Type","type":"select","required":false,"options":["Percentage","Fixed Amount"],"default":"Percentage"},{"name":"discount_value","label":"Discount Value","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"offer_description","label":"Offer Description","type":"textarea","required":false,"default":"Present this voucher at checkout to redeem the discount shown. One voucher per transaction unless otherwise stated."},{"name":"valid_from","label":"Valid From","type":"date","required":false},{"name":"valid_until","label":"Valid Until","type":"date","required":true},{"name":"terms","label":"Terms & Conditions","type":"textarea","required":false,"default":"This voucher has no cash value, cannot be combined with other offers unless stated, and is valid only within the dates shown. The issuer reserves the right to amend or withdraw the offer."}]}', faqs = '[{"q":"What should a discount voucher include to be valid?","a":"A redeemable voucher should show a unique code, the discount value or percentage, the valid-from and valid-until dates, and clear terms and conditions (such as one-per-customer or exclusions). These protect the business and set clear expectations for the customer."},{"q":"Can I create percentage or fixed-amount vouchers?","a":"Yes. Choose a percentage or a fixed amount, set the value and the validity window, and add any conditions. The voucher is branded with your business details and ready to print or share digitally."},{"q":"Can I download this Discount Voucher as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Discount Voucher suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'discount-voucher-generator';
UPDATE document_templates SET faqs = '[{"q":"What is an order confirmation?","a":"An order confirmation is sent by a seller to acknowledge that a customer''s order has been received and accepted, restating the items, prices, delivery date and terms. It reassures the customer and creates a shared record before fulfilment."},{"q":"How is it different from a sales order or invoice?","a":"An order confirmation acknowledges and accepts the order to the customer; a sales order is the seller''s internal commitment to fulfil it; an invoice later requests payment. Many businesses use the same reference across all three."},{"q":"Can I download this Order Confirmation as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Order Confirmation suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'order-confirmation-generator';
UPDATE document_templates SET faqs = '[{"q":"What is an RMA and why issue one?","a":"A Return Merchandise Authorization (RMA) formally approves a customer''s return and assigns a tracking number, recording the reason for return, the items, and the resolution (refund, replacement or repair). It controls returns and provides an audit trail for warranty and accounting purposes."},{"q":"What should an RMA include?","a":"An RMA number, the original order/invoice reference, the customer''s details, the items being returned with reasons, the authorised resolution, and any return-shipping instructions. Invoxaco captures all of these on one clear document."},{"q":"Can I download this Return Merchandise Authorization as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Return Merchandise Authorization suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'return-merchandise-authorization-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"sender","label":"From (Sender)","type":"party","required":true},{"name":"recipient","label":"To (Recipient)","type":"party","required":true},{"name":"subject","label":"Subject","type":"text","required":true},{"name":"conduct_complained_of","label":"Conduct Complained Of","type":"textarea","required":true,"default":"You are engaging in conduct that infringes the rights of the sender, as more particularly described below. This conduct is unlawful and must cease immediately."},{"name":"compliance_deadline","label":"Comply By (Date)","type":"date","required":true},{"name":"consequences","label":"Consequences of Non-Compliance","type":"textarea","required":false,"default":"If you fail to comply by the date stated above, the sender reserves all rights to pursue all available legal remedies, including injunctive relief and a claim for damages and legal costs, without further notice to you."},{"name":"body","label":"Letter Body","type":"textarea","required":true,"default":"This letter constitutes formal notice demanding that you immediately CEASE AND DESIST from the conduct described below. The sender takes this matter seriously and is prepared to enforce its rights to the fullest extent permitted by law. This letter is sent without prejudice to any of the sender''s rights and remedies, all of which are expressly reserved."},{"name":"closing","label":"Closing","type":"text","required":false,"default":"Yours faithfully,"},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title / Position","type":"text","required":false},{"name":"signatory_signature","label":"Signature","type":"signature","required":false}]}', faqs = '[{"q":"Is a cease and desist letter legally binding?","a":"A cease and desist letter is a formal demand, not a court order, so it is not itself binding. However, it puts the recipient on formal written notice, often resolves the matter without litigation, and creates important evidence that you asserted your rights — which strengthens any later court claim. For serious matters, have an attorney review or send it."},{"q":"What conduct can a cease and desist letter address?","a":"It is commonly used for intellectual-property infringement (trademark, copyright), defamation, harassment, breach of contract, debt collection, and breaches of confidentiality or non-compete obligations. Describe the specific conduct and the rights infringed as clearly as possible."},{"q":"Can I download this Cease and Desist Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Cease and Desist Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'cease-and-desist-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"sender","label":"From (Sender)","type":"party","required":true},{"name":"recipient","label":"To (Recipient)","type":"party","required":true},{"name":"subject","label":"Subject","type":"text","required":true},{"name":"basis_of_demand","label":"Basis of the Demand","type":"textarea","required":true,"default":"The recipient owes the sender the amount/obligation described below arising from the facts set out in this letter. Despite previous requests, the matter remains outstanding."},{"name":"amount_demanded","label":"Amount Demanded","type":"number","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"payment_deadline","label":"Pay / Respond By (Date)","type":"date","required":true},{"name":"consequences","label":"Consequences of Non-Payment","type":"textarea","required":false,"default":"If full payment (or a satisfactory response) is not received by the date specified, the sender intends to commence legal proceedings to recover the amount due together with interest, legal costs and any further relief the court considers appropriate, without further notice."},{"name":"body","label":"Letter Body","type":"textarea","required":true,"default":"This is a formal letter of demand. The sender requires that you settle the matter described below by the deadline stated. This letter is an attempt to resolve this matter amicably and to avoid the time and expense of litigation. It is sent without prejudice to the sender''s rights, all of which are expressly reserved."},{"name":"closing","label":"Closing","type":"text","required":false,"default":"Yours faithfully,"},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title / Position","type":"text","required":false},{"name":"signatory_signature","label":"Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is a letter of demand and when should I send one?","a":"A letter of demand is a formal written request for payment or for someone to fulfil a legal obligation, sent before starting court action. It is widely expected (and in many jurisdictions effectively required) as a final opportunity to resolve a dispute, and demonstrates to a court that you acted reasonably."},{"q":"What should a demand letter include to be effective?","a":"It should clearly identify the parties, state the factual and legal basis of the demand, specify the exact amount or action required, set a firm but reasonable deadline, and explain the consequences of non-compliance. Keeping a copy and proof of delivery is essential."},{"q":"Can I download this Demand Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Demand Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'demand-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"business_name","label":"Partnership / Business Name","type":"text","required":true},{"name":"business_purpose","label":"Business Purpose","type":"textarea","required":true,"default":"The partners agree to associate as partners for the purpose of carrying on the business described herein and to share in its profits and losses in the proportions set out in this Agreement."},{"name":"partner_1","label":"Partner 1","type":"party","required":true},{"name":"partner_2","label":"Partner 2","type":"party","required":true},{"name":"partner_3","label":"Partner 3","type":"party","required":false},{"name":"partner_4","label":"Partner 4","type":"party","required":false},{"name":"capital_contributions","label":"Capital Contributions","type":"textarea","required":true,"default":"Each partner shall contribute the capital set out against their name. The capital accounts shall be maintained for each partner and adjusted for further contributions, drawings and shares of profit or loss."},{"name":"profit_sharing","label":"Profit and Loss Sharing","type":"textarea","required":true,"default":"The net profits and losses of the partnership shall be divided among the partners in proportion to their respective capital contributions, unless the partners agree otherwise in writing."},{"name":"management_clause","label":"Management and Decision-Making","type":"textarea","required":true,"default":"The partners shall have equal rights in the management and conduct of the partnership business. Decisions in the ordinary course of business shall be made by majority; decisions outside the ordinary course, or that materially affect the partnership, shall require the unanimous consent of all partners."},{"name":"banking_clause","label":"Banking and Accounts","type":"textarea","required":false,"default":"The partnership shall maintain bank accounts in the partnership name. Proper books of account shall be kept and shall be open to inspection by any partner. Financial statements shall be prepared at the end of each financial year."},{"name":"admission_withdrawal","label":"Admission and Withdrawal of Partners","type":"textarea","required":true,"default":"No new partner shall be admitted without the unanimous written consent of the existing partners. A partner may withdraw on the notice period stated, and the continuing partners shall have the right to purchase the outgoing partner''s interest at fair value."},{"name":"dissolution_clause","label":"Dissolution and Winding Up","type":"textarea","required":true,"default":"On dissolution, the partnership assets shall be applied first to discharge liabilities, then to repay partners'' capital, and any surplus shall be distributed among the partners in their profit-sharing proportions."},{"name":"confidentiality_clause","label":"Confidentiality","type":"textarea","required":false,"default":"Each partner shall keep confidential all non-public information concerning the partnership and shall not use or disclose it except for the purposes of the partnership business or as required by law."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":true,"default":"Any dispute arising out of or in connection with this Agreement shall first be addressed through good-faith negotiation between the partners and, failing resolution, referred to mediation and then to binding arbitration or the competent courts of the agreed jurisdiction."},{"name":"non_compete_clause","label":"Non-Competition","type":"textarea","required":false,"default":"During the term of the partnership and for the agreed period afterwards, no partner shall, without consent, engage in any business that directly competes with the partnership within the agreed territory."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false,"default":"This document shall be governed by and construed in accordance with the laws of the applicable jurisdiction stated by the parties."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement constitutes the entire agreement among the partners and supersedes all prior understandings. It may be amended only in writing signed by all partners."},{"name":"partner_1_signature","label":"Partner 1 Signature","type":"signature","required":false},{"name":"partner_2_signature","label":"Partner 2 Signature","type":"signature","required":false},{"name":"partner_3_signature","label":"Partner 3 Signature","type":"signature","required":false},{"name":"partner_4_signature","label":"Partner 4 Signature","type":"signature","required":false}]}', faqs = '[{"q":"How many partners can this agreement cover?","a":"The template supports up to four named partners, each with their own details, capital contribution and signature block, and can be adapted for fewer. It sets out capital, profit-sharing, management, admission and withdrawal, dissolution and dispute-resolution terms expected of a professional partnership agreement internationally."},{"q":"Is a written partnership agreement necessary?","a":"While partnerships can arise informally, a written agreement is strongly recommended everywhere. Without one, default partnership law in your jurisdiction decides profit-sharing, decision-making and exit terms — often in ways the partners did not intend. A clear written agreement prevents disputes."},{"q":"Can I download this Multi-Partner Agreement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Multi-Partner Agreement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'multi-partner-agreement-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"employer","label":"Employer","type":"party","required":true},{"name":"candidate","label":"Candidate","type":"party","required":true},{"name":"job_title","label":"Job Title","type":"text","required":true},{"name":"department","label":"Department","type":"text","required":false},{"name":"employment_type","label":"Employment Type","type":"select","required":false,"options":["Full-Time","Part-Time","Fixed-Term","Temporary","Contract"],"default":"Full-Time"},{"name":"start_date","label":"Proposed Start Date","type":"date","required":true},{"name":"reporting_to","label":"Reporting To","type":"text","required":false},{"name":"work_location","label":"Work Location","type":"text","required":false},{"name":"annual_salary","label":"Annual Salary / Compensation","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"benefits","label":"Benefits","type":"textarea","required":false,"default":"The role includes the standard benefits package offered to employees of this category, details of which will be provided on joining."},{"name":"conditions","label":"Conditions of Offer","type":"textarea","required":false,"default":"This offer is conditional upon satisfactory references, proof of eligibility to work, and completion of any background checks required for the role."},{"name":"offer_valid_until","label":"Offer Valid Until","type":"date","required":false},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"We are delighted to offer you the position described below. We were impressed by your background and believe you will be a valuable addition to our team. Please review the terms of this offer and confirm your acceptance by signing and returning a copy by the date indicated."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title","type":"text","required":false},{"name":"signatory_signature","label":"Employer Signature","type":"signature","required":false},{"name":"candidate_signature","label":"Candidate Acceptance Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a professional job offer letter include?","a":"A complete offer letter states the job title, employment type, start date, reporting line, work location, salary and benefits, any conditions (references, right-to-work, background checks), and how to accept. Providing a clear, written offer is best practice and is expected by candidates internationally."},{"q":"Is this HR document legally compliant in my country?","a":"The template follows internationally accepted HR practice and neutral wording suitable for the US, UK, EU and many other countries. Employment law is highly jurisdiction-specific, however — statutory notice periods, minimum terms and protected rights vary — so set your governing law and have local HR or legal counsel confirm mandatory local requirements before issuing."},{"q":"Can I download this Job Offer Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Job Offer Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'offer-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"employer","label":"Employer","type":"party","required":true},{"name":"employee","label":"Employee","type":"party","required":true},{"name":"job_title","label":"Job Title / Position","type":"text","required":false},{"name":"termination_type","label":"Type of Termination","type":"select","required":false,"options":["With Notice","For Cause","Redundancy / Layoff","End of Fixed Term","Mutual Separation"],"default":"With Notice"},{"name":"termination_effective_date","label":"Effective Date of Termination","type":"date","required":true},{"name":"notice_period","label":"Notice Period","type":"text","required":false},{"name":"reason","label":"Reason for Termination","type":"textarea","required":false,"default":"Your employment is being terminated for the reason indicated. This decision has been made in accordance with company policy and applicable law."},{"name":"final_settlement","label":"Final Settlement & Return of Property","type":"textarea","required":false,"default":"Your final salary, accrued leave and any other entitlements will be settled in accordance with company policy and applicable law. Please return all company property on or before your last working day."},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"This letter is to formally notify you that your employment with the company will end on the date stated below. We thank you for your service and wish you well in your future endeavours."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title","type":"text","required":false},{"name":"signatory_signature","label":"Employer Signature","type":"signature","required":false}]}', faqs = '[{"q":"How do I write a termination letter that reduces legal risk?","a":"Keep it factual and respectful: state the effective date, the type and (where appropriate) reason for termination, the notice given, and how final pay, accrued leave and company property will be handled. Follow your contractual and statutory notice obligations and any required process — wrongful or unfair dismissal claims often turn on process, not just reason."},{"q":"Is this HR document legally compliant in my country?","a":"The template follows internationally accepted HR practice and neutral wording suitable for the US, UK, EU and many other countries. Employment law is highly jurisdiction-specific, however — statutory notice periods, minimum terms and protected rights vary — so set your governing law and have local HR or legal counsel confirm mandatory local requirements before issuing."},{"q":"Can I download this Termination Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Termination Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'termination-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"employer","label":"Employer","type":"party","required":true},{"name":"employee","label":"Employee","type":"party","required":true},{"name":"warning_level","label":"Warning Level","type":"select","required":false,"options":["Verbal (Confirmed in Writing)","First Written Warning","Second Written Warning","Final Written Warning"],"default":"First Written Warning"},{"name":"subject","label":"Subject","type":"text","required":false,"default":"Disciplinary Warning"},{"name":"issue_description","label":"Description of Issue / Misconduct","type":"textarea","required":true,"default":"This letter concerns the conduct or performance issue described below, which has been identified as falling short of the standards expected and required of you."},{"name":"expected_improvement","label":"Required Improvement","type":"textarea","required":true,"default":"You are required to improve in the areas described, with immediate effect. Specific expectations and any support available are set out below."},{"name":"review_period","label":"Review Period","type":"text","required":false,"default":"30 days"},{"name":"consequences","label":"Consequences of Non-Improvement","type":"textarea","required":false,"default":"Failure to demonstrate and sustain the required improvement may result in further disciplinary action, up to and including termination of employment."},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"This letter is a formal warning issued under the company''s disciplinary procedure. Its purpose is to make you aware of the concern and to give you the opportunity to improve."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title","type":"text","required":false},{"name":"signatory_signature","label":"Employer Signature","type":"signature","required":false},{"name":"employee_signature","label":"Employee Acknowledgement","type":"signature","required":false}]}', faqs = '[{"q":"How should a disciplinary warning letter be structured?","a":"It should identify the specific conduct or performance issue, reference the standard or policy breached, state the required improvement and review period, explain the consequences of non-improvement, and give the employee a chance to respond. A graduated process (verbal, first written, final written) is best practice and helps defend against unfair-dismissal claims."},{"q":"Is this HR document legally compliant in my country?","a":"The template follows internationally accepted HR practice and neutral wording suitable for the US, UK, EU and many other countries. Employment law is highly jurisdiction-specific, however — statutory notice periods, minimum terms and protected rights vary — so set your governing law and have local HR or legal counsel confirm mandatory local requirements before issuing."},{"q":"Can I download this Employee Warning Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Employee Warning Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'employee-warning-letter-generator';
