g suitable for the US, UK, EU and many other countries. Employment law is highly jurisdiction-specific, however — statutory notice periods, minimum terms and protected rights vary — so set your governing law and have local HR or legal counsel confirm mandatory local requirements before issuing."},{"q":"Can I download this Promotion Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Promotion Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'promotion-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"employer","label":"Employer","type":"party","required":true},{"name":"employee","label":"Employee","type":"party","required":true},{"name":"job_title","label":"Job Title","type":"text","required":false},{"name":"date_of_joining","label":"Date of Joining","type":"date","required":false},{"name":"last_working_day","label":"Last Working Day","type":"date","required":true},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"This letter confirms that the employee named below has been relieved of their duties with effect from the last working day stated, following acceptance of their resignation. All company responsibilities have been satisfactorily handed over. We confirm that the employee is free to take up other employment and we wish them success in their future endeavours."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title","type":"text","required":false},{"name":"signatory_signature","label":"Employer Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is a relieving letter and why is it important?","a":"A relieving letter is issued by an employer at the end of employment to confirm that the employee has been formally released from their duties and has completed handover. New employers frequently request it as proof of clean separation from a previous job, so it is an important document for the employee''s records."},{"q":"How is a relieving letter different from an experience certificate?","a":"A relieving letter confirms the date of release and that the employee left in good order; an experience certificate describes the role, tenure and (often) conduct and performance. Many employers issue both on an employee''s last day."},{"q":"Can I download this Relieving Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Relieving Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'relieving-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"issue_date","label":"Date of Issue","type":"date","required":true},{"name":"employer","label":"Issuing Organization","type":"party","required":true},{"name":"employee_name","label":"Employee Name","type":"text","required":true},{"name":"employee_id","label":"Employee ID","type":"text","required":false},{"name":"job_title","label":"Job Title / Designation","type":"text","required":true},{"name":"department","label":"Department","type":"text","required":false},{"name":"employment_from","label":"Employed From","type":"date","required":true},{"name":"employment_to","label":"Employed To","type":"date","required":true},{"name":"responsibilities","label":"Roles & Responsibilities","type":"textarea","required":false,"default":"During this period the employee carried out the duties of their role competently and professionally, contributing positively to the team and the organisation."},{"name":"conduct_remark","label":"Conduct & Performance Remark","type":"textarea","required":false,"default":"We found the employee to be diligent, reliable and of good character throughout their tenure. We wish them every success in their future career."},{"name":"signatory_name","label":"Authorized Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Designation","type":"text","required":false},{"name":"signatory_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should an experience (service) certificate contain?","a":"It should be on company letterhead and state the employee''s full name, designation, department, the exact dates of employment, a summary of responsibilities, and a remark on conduct and performance, signed by an authorised representative. It serves as formal proof of work experience for future employers worldwide."},{"q":"Is an experience certificate the same as a reference letter?","a":"They overlap but differ: an experience certificate is a factual confirmation of employment and tenure, while a reference letter is a more personal recommendation of the individual''s abilities. This template focuses on the formal experience certificate, with an optional conduct remark."},{"q":"Can I download this Experience Certificate as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Experience Certificate suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'experience-certificate-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"employer","label":"Employer","type":"party","required":true},{"name":"employee","label":"Employee","type":"party","required":true},{"name":"job_title","label":"Job Title","type":"text","required":true},{"name":"department","label":"Department","type":"text","required":false},{"name":"employment_type","label":"Employment Type","type":"select","required":false,"options":["Full-Time","Part-Time","Fixed-Term","Temporary","Contract"],"default":"Full-Time"},{"name":"joining_date","label":"Date of Joining","type":"date","required":true},{"name":"salary","label":"Salary / Compensation","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"probation_period","label":"Probation Period","type":"text","required":false,"default":"Six (6) months"},{"name":"notice_period","label":"Notice Period","type":"text","required":false,"default":"One (1) month"},{"name":"work_hours","label":"Working Hours","type":"text","required":false},{"name":"terms","label":"Terms of Appointment","type":"textarea","required":false,"default":"Your employment is governed by the company''s policies and the terms set out in this letter and any accompanying contract. You are expected to perform your duties diligently and to comply with all applicable policies and procedures."},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"Further to your acceptance of our offer, we are pleased to confirm your appointment on the terms set out below. We look forward to a long and successful association."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title","type":"text","required":false},{"name":"signatory_signature","label":"Employer Signature","type":"signature","required":false},{"name":"employee_signature","label":"Employee Acknowledgement","type":"signature","required":false}]}', faqs = '[{"q":"What is the difference between an offer letter and an appointment letter?","a":"An offer letter proposes a role and invites the candidate to accept; an appointment letter formally confirms the appointment after acceptance and sets out the binding terms of employment such as joining date, salary, probation and notice period. Many employers issue both."},{"q":"Is this HR document legally compliant in my country?","a":"The template follows internationally accepted HR practice and neutral wording suitable for the US, UK, EU and many other countries. Employment law is highly jurisdiction-specific, however — statutory notice periods, minimum terms and protected rights vary — so set your governing law and have local HR or legal counsel confirm mandatory local requirements before issuing."},{"q":"Can I download this Appointment Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Appointment Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'appointment-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"employee","label":"Your Details (Employee)","type":"party","required":true},{"name":"employer","label":"Addressed To (Employer / Manager)","type":"party","required":true},{"name":"job_title","label":"Your Position","type":"text","required":false},{"name":"last_working_day","label":"Proposed Last Working Day","type":"date","required":true},{"name":"notice_period","label":"Notice Period","type":"text","required":false},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"Please accept this letter as formal notice of my resignation from my position, effective from the last working day stated below, in accordance with my notice period. I am grateful for the opportunities and support I have received during my time here and will do everything I can to ensure a smooth and thorough handover of my responsibilities."},{"name":"gratitude","label":"Closing Remarks","type":"textarea","required":false,"default":"Thank you again for the experience and professional development I have gained. I wish the organisation continued success and hope to stay in touch."},{"name":"employee_signature","label":"Your Signature","type":"signature","required":false}]}', faqs = '[{"q":"How do I write a professional resignation letter?","a":"Keep it brief, positive and clear: state that you are resigning, give your last working day in line with your notice period, offer to support the handover, and thank your employer. Avoid criticism — a gracious resignation protects your professional reputation and future references."},{"q":"How much notice should I give?","a":"Give at least the notice period stated in your employment contract; one month (or the local statutory minimum) is common for many roles, while senior positions may require more. Confirm your contractual notice and last working day in the letter."},{"q":"Can I download this Resignation Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Resignation Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'resignation-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"organization_name","label":"Organization","type":"text","required":true},{"name":"form_title","label":"Form Title","type":"text","required":true,"default":"Performance Review Form"},{"name":"employee_name","label":"Employee Name","type":"text","required":true},{"name":"employee_id","label":"Employee ID","type":"text","required":false},{"name":"job_title","label":"Job Title","type":"text","required":false},{"name":"department","label":"Department","type":"text","required":false},{"name":"reviewer_name","label":"Reviewer / Manager Name","type":"text","required":true},{"name":"review_period_from","label":"Review Period From","type":"date","required":true},{"name":"review_period_to","label":"Review Period To","type":"date","required":true},{"name":"objectives","label":"Objectives & Ratings","type":"line_items","required":true},{"name":"strengths","label":"Key Strengths","type":"textarea","required":false,"default":"Summarise the employee''s main strengths and notable achievements during the review period."},{"name":"areas_for_development","label":"Areas for Development","type":"textarea","required":false,"default":"Identify specific areas where the employee can develop, with concrete, supportive suggestions."},{"name":"goals_next_period","label":"Goals for Next Period","type":"textarea","required":false,"default":"Set clear, measurable objectives for the coming review period, agreed between employee and manager."},{"name":"overall_rating","label":"Overall Rating","type":"select","required":false,"options":["Outstanding","Exceeds Expectations","Meets Expectations","Needs Improvement","Unsatisfactory"],"default":"Meets Expectations"},{"name":"employee_comments","label":"Employee Comments","type":"textarea","required":false},{"name":"reviewer_signature","label":"Reviewer Signature","type":"signature","required":false},{"name":"employee_signature","label":"Employee Signature","type":"signature","required":false}]}', faqs = '[{"q":"What makes a performance review fair and effective?","a":"An effective review is based on the period''s agreed objectives, balances strengths with development areas, sets clear measurable goals for the next period, and gives the employee space to comment. Documenting reviews consistently supports fair pay, promotion and, where necessary, performance-management decisions."},{"q":"Should both the manager and employee sign the review?","a":"Yes. Both signatures confirm the review was discussed (not necessarily that the employee agrees with every point) and create a dated record. Include an employee-comments section so the employee can add their perspective."},{"q":"Can I download this Performance Review Form as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Performance Review Form suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'performance-review-form-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"handbook_title","label":"Handbook Title","type":"text","required":true,"default":"Employee Handbook"},{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"version","label":"Version","type":"text","required":false,"default":"1.0"},{"name":"welcome_message","label":"Welcome Message","type":"textarea","required":false,"default":"Welcome to our team. This handbook introduces our company, our values and the policies and standards that guide how we work together. Please read it carefully and keep it for reference."},{"name":"company_values","label":"Mission & Values","type":"textarea","required":false,"default":"Our mission and core values define who we are and how we treat our colleagues, customers and partners."},{"name":"code_of_conduct","label":"Code of Conduct","type":"textarea","required":false,"default":"All employees are expected to act with integrity, treat others with respect, avoid conflicts of interest, and comply with all applicable laws and company policies."},{"name":"working_hours_leave","label":"Working Hours & Leave","type":"textarea","required":false,"default":"Standard working hours, attendance expectations, and entitlements to annual, sick and other leave are described in this section in line with applicable law."},{"name":"compensation_benefits","label":"Compensation & Benefits","type":"textarea","required":false,"default":"This section outlines how and when employees are paid and the benefits available to them."},{"name":"conduct_discipline","label":"Conduct, Discipline & Grievances","type":"textarea","required":false,"default":"Procedures for addressing performance and conduct issues, and for raising grievances, are set out to ensure fair and consistent treatment."},{"name":"health_safety","label":"Health, Safety & Equal Opportunity","type":"textarea","required":false,"default":"We are committed to a safe, inclusive workplace free from discrimination and harassment, and to equal opportunity for all employees."},{"name":"confidentiality_it","label":"Confidentiality & IT Use","type":"textarea","required":false,"default":"Employees must protect confidential information and use company systems and data responsibly and in line with policy."},{"name":"acknowledgement","label":"Acknowledgement","type":"textarea","required":false,"default":"I acknowledge that I have received, read and understood this Employee Handbook and agree to comply with its policies."},{"name":"employee_signature","label":"Employee Acknowledgement Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should an employee handbook cover?","a":"A professional handbook covers your mission and values, code of conduct, working hours and leave, compensation and benefits, health and safety, equal-opportunity and anti-harassment policies, confidentiality and IT use, and disciplinary and grievance procedures — ending with an acknowledgement the employee signs."},{"q":"Is an employee handbook legally binding?","a":"A handbook is primarily a policy and communication document, but parts of it can create binding obligations depending on jurisdiction and wording. Make clear which policies are contractual and which are guidance, keep it consistent with employment contracts and local law, and have it reviewed where employees are in multiple countries."},{"q":"Can I download this Employee Handbook as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Employee Handbook suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'employee-handbook-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Contractor","type":"text","required":true},{"name":"work_order_number","label":"Work Order No.","type":"text","required":true},{"name":"issue_date","label":"Issue Date","type":"date","required":true},{"name":"client","label":"Client","type":"party","required":true},{"name":"project_name","label":"Project / Site Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"supervisor","label":"Supervisor / Foreman","type":"text","required":false},{"name":"start_date","label":"Scheduled Start Date","type":"date","required":false},{"name":"completion_date","label":"Scheduled Completion Date","type":"date","required":false},{"name":"scope_of_work","label":"Scope of Work","type":"textarea","required":true,"default":"The contractor shall carry out the works described below in a good and workmanlike manner, in accordance with the relevant drawings, specifications and applicable building codes and safety regulations."},{"name":"items","label":"Work / Materials","type":"line_items","required":true,"has_unit":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"notes","label":"Notes / Special Instructions","type":"textarea","required":false,"default":"All works shall comply with site health-and-safety requirements. Any variation to this work order must be agreed in writing before the additional work is carried out."},{"name":"authorized_by","label":"Authorized By","type":"text","required":false},{"name":"authorized_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is a work order and what should it contain?","a":"A work order authorises and records specific work to be performed: a unique number, the client and site, the supervisor, the scope of work, scheduled dates, materials and labour, and an authorising signature. It controls what is done on site and supports accurate billing and dispute resolution."},{"q":"How does a work order relate to a change order?","a":"A work order authorises the originally agreed scope; a change order documents any addition or variation to that scope, with its own pricing and approval. Keeping the two separate maintains a clear audit trail of what was authorised and when."},{"q":"Can I download this Work Order as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Work Order suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'work-order-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Contractor","type":"text","required":true},{"name":"change_order_number","label":"Change Order No.","type":"text","required":true},{"name":"contract_reference","label":"Original Contract / Work Order Ref","type":"text","required":false},{"name":"issue_date","label":"Issue Date","type":"date","required":true},{"name":"client","label":"Client","type":"party","required":true},{"name":"project_name","label":"Project / Site Name","type":"text","required":true},{"name":"description_of_change","label":"Description of Change","type":"textarea","required":true,"default":"This change order describes a variation to the originally agreed scope of work. The change has been requested and is documented below for approval before any additional work proceeds."},{"name":"reason","label":"Reason for Change","type":"textarea","required":false,"default":"The change arises from the circumstances described and is necessary to deliver the project as required."},{"name":"cost_items","label":"Cost Impact (Additions / Deductions)","type":"line_items","required":true,"has_unit":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"schedule_impact","label":"Impact on Schedule","type":"text","required":false,"default":"The completion date is adjusted as stated to reflect this change."},{"name":"terms","label":"Terms","type":"textarea","required":false,"default":"This change order, once signed by both parties, forms part of the contract. No additional work covered by this change shall commence until written approval is given."},{"name":"contractor_signature","label":"Contractor Signature","type":"signature","required":false},{"name":"client_signature","label":"Client Approval Signature","type":"signature","required":false}]}', faqs = '[{"q":"Why are change orders important in construction projects?","a":"Change orders document every variation to the agreed scope, cost and schedule, and require approval before extra work proceeds. They prevent disputes over unauthorised work and ''scope creep'', protect the contractor''s right to be paid for extras, and give the client cost control."},{"q":"Should both parties sign a change order before work starts?","a":"Yes. A change order should be agreed and signed by both the contractor and the client before the additional work begins. This confirms the revised price and schedule and avoids later disagreement about whether the work — and its cost — was authorised."},{"q":"Can I download this Change Order as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Change Order suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'change-order-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Department","type":"text","required":true},{"name":"requisition_number","label":"Requisition No.","type":"text","required":true},{"name":"request_date","label":"Date","type":"date","required":true},{"name":"project_name","label":"Project / Site","type":"text","required":false},{"name":"requested_by","label":"Requested By","type":"text","required":true},{"name":"delivery_location","label":"Delivery Location","type":"text","required":false},{"name":"required_by","label":"Required By Date","type":"date","required":false},{"name":"materials","label":"Materials Requested","type":"line_items","required":true,"has_unit":true},{"name":"purpose","label":"Purpose / Justification","type":"textarea","required":false,"default":"The materials listed are required for the works described and are requested in the quantities shown."},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"approved_signature","label":"Approval Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is a material requisition form used for?","a":"A material requisition formally requests materials from stores or procurement, recording what is needed, the quantities, the project or cost centre, the required-by date, and an approval. It controls material issue, supports inventory accuracy and creates an audit trail for project costing."},{"q":"Who should approve a material requisition?","a":"Requisitions should be approved by an authorised person (such as a site manager or project lead) before materials are issued or purchased. This control prevents over-ordering and ensures materials are charged to the correct project."},{"q":"Can I download this Material Requisition as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Material Requisition suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'material-requisition-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company","type":"text","required":true},{"name":"report_number","label":"Report No.","type":"text","required":false},{"name":"project_name","label":"Project / Site Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"inspection_date","label":"Inspection Date","type":"date","required":true},{"name":"inspector_name","label":"Inspector Name","type":"text","required":true},{"name":"weather_conditions","label":"Weather Conditions","type":"text","required":false},{"name":"work_in_progress","label":"Work in Progress","type":"text","required":false},{"name":"observations","label":"Observations & Findings","type":"line_items","required":true},{"name":"safety_observations","label":"Health & Safety Observations","type":"textarea","required":false,"default":"Site conditions were assessed against applicable health-and-safety requirements. Any hazards or non-compliances identified are recorded below with the action required."},{"name":"recommendations","label":"Recommendations / Actions Required","type":"textarea","required":false,"default":"The actions listed below are recommended to address the findings of this inspection, with responsibilities and timescales as noted."},{"name":"inspector_title","label":"Inspector Title","type":"text","required":false},{"name":"inspector_signature","label":"Inspector Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a construction site inspection report record?","a":"It should record the project and date, the inspector, weather and work in progress, detailed observations on quality and progress, health-and-safety findings, and clear recommended actions with responsibilities. A consistent, signed report protects all parties and supports compliance with safety regulations."},{"q":"Why are regular site inspections important?","a":"Regular documented inspections catch defects and safety hazards early, evidence compliance with building codes and safety law, support progress claims, and provide a contemporaneous record that is invaluable if a quality or liability dispute arises later."},{"q":"Can I download this Site Inspection Report as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Site Inspection Report suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'site-inspection-report-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Contractor","type":"text","required":true},{"name":"estimate_number","label":"Estimate No.","type":"text","required":true},{"name":"estimate_date","label":"Date","type":"date","required":true},{"name":"client","label":"Client","type":"party","required":true},{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"scope","label":"Scope of Work","type":"textarea","required":false,"default":"This estimate covers the works described below. It is based on the information currently available and on the assumptions noted; the final cost may vary if the scope, specifications or site conditions change."},{"name":"items","label":"Estimated Costs (Labour & Materials)","type":"line_items","required":true,"has_unit":true,"per_item_tax":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"contingency_percent","label":"Contingency (%)","type":"number","required":false},{"name":"valid_until","label":"Estimate Valid Until","type":"date","required":false},{"name":"terms","label":"Terms & Assumptions","type":"textarea","required":false,"default":"This is an estimate, not a fixed-price quotation, unless stated otherwise. Prices are valid until the date shown and exclude any work not expressly listed. Variations will be priced separately by change order."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is the difference between an estimate and a quotation?","a":"An estimate is an informed approximation of likely cost based on current information and may change as scope or conditions become clearer; a quotation is a fixed price the contractor commits to. Make clear which you are providing — this template is set up as an estimate with assumptions and a contingency."},{"q":"Should a construction estimate include a contingency?","a":"Yes. A contingency allowance covers unforeseen conditions and minor scope changes and is standard professional practice. State the contingency percentage and the key assumptions so the client understands what is and is not included."},{"q":"Can I download this Construction Estimate as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Construction Estimate suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'construction-estimate-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"contractor","label":"Contractor","type":"party","required":false},{"name":"client","label":"Client / Owner","type":"party","required":false},{"name":"inspection_date","label":"Inspection Date","type":"date","required":true},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"punch_items","label":"Punch List Items","type":"line_items","required":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"The items listed below remain outstanding or require correction before the works can be accepted as complete. Each item should be rectified and signed off by the responsible party."},{"name":"target_completion","label":"Target Completion Date","type":"text","required":false},{"name":"contractor_signature","label":"Contractor Signature","type":"signature","required":false},{"name":"client_signature","label":"Client Sign-Off","type":"signature","required":false}]}', faqs = '[{"q":"What is a punch list (snagging list) in construction?","a":"A punch list — known as a snagging list in the UK — records the outstanding or defective items that must be completed or corrected before a project is accepted as finished. It is prepared at near-completion and signed off as each item is resolved, protecting both contractor and client."},{"q":"When is a punch list prepared?","a":"It is typically prepared during the final walkthrough as the project nears substantial completion. Resolving every punch-list item is usually a condition of final payment and formal handover of the works."},{"q":"Can I download this Punch List as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Punch List suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'punch-list-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"log_date","label":"Date","type":"date","required":true},{"name":"prepared_by","label":"Prepared By / Supervisor","type":"text","required":true},{"name":"weather_conditions","label":"Weather Conditions","type":"text","required":false},{"name":"workers_on_site","label":"Number of Workers on Site","type":"number","required":false},{"name":"work_performed","label":"Work Performed","type":"line_items","required":true},{"name":"equipment_used","label":"Equipment & Materials Used","type":"line_items","required":true},{"name":"delays_issues","label":"Delays / Issues","type":"textarea","required":false,"default":"Record any delays, disruptions, safety incidents or issues encountered on site today, with their cause and impact."},{"name":"visitors","label":"Site Visitors / Deliveries","type":"textarea","required":false},{"name":"supervisor_signature","label":"Supervisor Signature","type":"signature","required":false}]}', faqs = '[{"q":"Why keep a daily construction work log?","a":"A daily log creates a contemporaneous record of labour, equipment, work performed, weather, deliveries and any delays or incidents. These records are invaluable for tracking progress, supporting payment claims, and resolving delay or disruption disputes, where day-by-day evidence is often decisive."},{"q":"What should be recorded in a daily site log?","a":"Record the date and weather, the number of workers, the work performed, equipment and materials used, site visitors and deliveries, and any delays, issues or safety incidents — signed by the site supervisor. Consistency matters more than length."},{"q":"Can I download this Daily Work Log as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Daily Work Log suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'daily-work-log-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Contractor","type":"text","required":true},{"name":"bid_number","label":"Bid / Proposal No.","type":"text","required":true},{"name":"bid_date","label":"Date","type":"date","required":true},{"name":"client","label":"Client / Owner","type":"party","required":true},{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"project_overview","label":"Project Overview","type":"textarea","required":false,"default":"We are pleased to submit our proposal for the project described below. This bid sets out our understanding of the scope, our proposed approach, pricing and timeline."},{"name":"scope_of_work","label":"Scope of Work","type":"textarea","required":true,"default":"Our proposal covers the works described below, to be carried out to the relevant specifications and applicable codes and standards."},{"name":"pricing","label":"Pricing Breakdown","type":"line_items","required":true,"has_unit":true,"per_item_tax":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"project_duration","label":"Estimated Duration","type":"text","required":false},{"name":"terms","label":"Terms & Conditions","type":"textarea","required":false,"default":"This bid is valid for the period stated and is based on the scope and assumptions described. It excludes work not expressly listed. Payment terms and a programme will be agreed on award. Variations will be handled by change order."},{"name":"valid_until","label":"Bid Valid Until","type":"date","required":false},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"prepared_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a winning construction bid proposal include?","a":"A strong bid clearly demonstrates understanding of the project, sets out the scope and approach, provides a transparent priced breakdown, states the duration and key assumptions, and includes professional terms and a validity period. Clarity and completeness build client confidence and reduce later disputes."},{"q":"How long should a bid remain valid?","a":"State a clear validity period (commonly 30–90 days) so pricing is protected against cost changes. Make explicit what the price includes and excludes, and note that variations will be priced separately, so the client compares bids on a like-for-like basis."},{"q":"Can I download this Bid Proposal as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Bid Proposal suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'bid-proposal-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Issuing Company","type":"text","required":true},{"name":"certificate_number","label":"Certificate No.","type":"text","required":false},{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"site_address","label":"Site Address","type":"text","required":false},{"name":"client","label":"Client / Owner","type":"party","required":true},{"name":"contractor","label":"Contractor","type":"party","required":false},{"name":"contract_start_date","label":"Contract Start Date","type":"date","required":false},{"name":"completion_date","label":"Date of Completion","type":"date","required":true},{"name":"certification_statement","label":"Certification Statement","type":"textarea","required":false,"default":"This is to certify that the works described above have been completed in accordance with the contract documents, drawings and specifications, and applicable codes and standards, and are hereby accepted as substantially complete as of the completion date stated."},{"name":"outstanding_items","label":"Outstanding Items (if any)","type":"textarea","required":false,"default":"Any minor outstanding items are recorded on the attached punch/snagging list and shall be completed within the agreed period; their existence does not affect substantial completion."},{"name":"warranty_note","label":"Defects Liability / Warranty","type":"textarea","required":false,"default":"The contractor''s defects-liability (warranty) period commences on the date of completion certified above, in accordance with the contract."},{"name":"certified_by","label":"Certified By","type":"text","required":false},{"name":"certifier_title","label":"Title","type":"text","required":false},{"name":"certifier_signature","label":"Authorized Signature","type":"signature","required":false},{"name":"client_signature","label":"Client Acceptance","type":"signature","required":false}]}', faqs = '[{"q":"What is a project completion certificate and why does it matter?","a":"A completion certificate formally records that the works have been completed to the contract requirements and accepted by the client as of a stated date. It commonly triggers final payment, the start of the defects-liability (warranty) period, the release of retention, and the transfer of risk for the works."},{"q":"Does completion mean every item is finished?","a":"Usually it certifies ''substantial completion'' — the works are usable for their intended purpose, with only minor punch/snag items outstanding. Those items are listed and completed within an agreed period without affecting the certificate or the start of the warranty period."},{"q":"Can I download this Project Completion Certificate as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Project Completion Certificate suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'project-completion-certificate-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"agreement_date","label":"Agreement Date","type":"date","required":true},{"name":"landlord","label":"Landlord / Lessor","type":"party","required":true},{"name":"tenant","label":"Tenant / Lessee","type":"party","required":true},{"name":"property_address","label":"Property Address & Description","type":"textarea","required":true,"default":"The landlord agrees to let and the tenant agrees to take the residential/commercial property described above, together with its fixtures and fittings, for the term and on the conditions set out in this Agreement."},{"name":"tenancy_type","label":"Tenancy Type","type":"select","required":false,"options":["Fixed-Term","Month-to-Month","Periodic"],"default":"Fixed-Term"},{"name":"lease_start","label":"Lease Start Date","type":"date","required":true},{"name":"lease_end","label":"Lease End Date","type":"date","required":false},{"name":"monthly_rent","label":"Monthly Rent","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"rent_due_day","label":"Rent Due Day","type":"text","required":false,"default":"1st of each month"},{"name":"security_deposit","label":"Security Deposit","type":"number","required":false},{"name":"payment_method","label":"Payment Method","type":"text","required":false},{"name":"use_of_premises","label":"Use of Premises","type":"textarea","required":false,"default":"The premises shall be used solely for the purpose stated and in a lawful, tenant-like manner. The tenant shall not cause nuisance or make alterations without the landlord''s prior written consent."},{"name":"maintenance_clause","label":"Repairs & Maintenance","type":"textarea","required":true,"default":"The landlord shall keep the structure and exterior in good repair and ensure installations for water, gas, electricity and sanitation are maintained. The tenant shall keep the interior clean and in good condition, fair wear and tear excepted, and promptly report any disrepair."},{"name":"utilities_clause","label":"Utilities & Outgoings","type":"textarea","required":false,"default":"Responsibility for utilities, council/property taxes and service charges is allocated between the parties as set out here; unless stated otherwise, the tenant is responsible for consumption-based utilities."},{"name":"deposit_clause","label":"Security Deposit Terms","type":"textarea","required":true,"default":"The deposit shall be held as security against damage, unpaid rent and breach of this Agreement, and returned within the period required by law after the tenant vacates, less any lawful deductions, which shall be itemised."},{"name":"entry_clause","label":"Right of Entry","type":"textarea","required":false,"default":"The landlord may enter the premises for inspection or repairs on reasonable prior notice (except in an emergency), and shall not interfere with the tenant''s quiet enjoyment of the property."},{"name":"termination_clause","label":"Termination & Notice","type":"textarea","required":true,"default":"Either party may terminate this Agreement by giving the notice period required by this Agreement and applicable law. On termination the tenant shall return the premises and all keys in the condition required by this Agreement."},{"name":"default_clause","label":"Default & Remedies","type":"textarea","required":false,"default":"If the tenant fails to pay rent or breaches this Agreement, the landlord may, subject to applicable law and any required notice, pursue available remedies including recovery of arrears and possession of the premises."},{"name":"liability_clause","label":"Liability & Insurance","type":"textarea","required":false,"default":"Each party is responsible for insuring its own property and interests. Neither party is liable for loss or damage to the other''s property except to the extent caused by its negligence or breach of this Agreement."},{"name":"dispute_resolution_clause","label":"Dispute Resolution","type":"textarea","required":false,"default":"The parties shall attempt to resolve any dispute amicably and, failing that, through mediation or the competent courts/tribunal of the jurisdiction in which the property is located."},{"name":"governing_law","label":"Governing Law / Jurisdiction","type":"text","required":false,"default":"This document shall be governed by and construed in accordance with the laws of the applicable jurisdiction stated by the parties."},{"name":"entire_agreement_clause","label":"Entire Agreement","type":"textarea","required":false,"default":"This Agreement, together with any inventory and attached schedules, constitutes the entire agreement between the parties and may be amended only in writing signed by both parties."},{"name":"landlord_signature","label":"Landlord Signature","type":"signature","required":false},{"name":"tenant_signature","label":"Tenant Signature","type":"signature","required":false},{"name":"witness_signature","label":"Witness Signature","type":"signature","required":false}]}', faqs = '[{"q":"Is this rental agreement valid in my country or state?","a":"It uses a neutral, professional structure with the core terms expected in a residential or commercial tenancy — rent, deposit, repairs, entry, termination and dispute resolution. Because landlord-tenant law (deposit protection, notice periods, eviction process) is highly local, set the governing law to where the property is located and check mandatory local requirements; for regulated tenancies have a local professional review it."},{"q":"What essential clauses should every lease include?","a":"At minimum: the parties and property, the term and rent, the security deposit terms, repair and maintenance responsibilities, utilities, the right of entry, termination and notice, and a dispute-resolution and governing-law clause. This template includes all of these plus signature blocks for the landlord, tenant and a witness."},{"q":"Can I download this Rental / Lease Agreement as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Rental / Lease Agreement suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'rental-agreement-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"listing_title","label":"Listing Title","type":"text","required":true,"default":"Property For Sale / Rent"},{"name":"listing_type","label":"Listing Type","type":"select","required":false,"options":["For Sale","For Rent","For Lease"],"default":"For Sale"},{"name":"property_type","label":"Property Type","type":"text","required":false,"default":"Residential"},{"name":"address","label":"Property Address","type":"text","required":true},{"name":"price","label":"Price / Rent","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"bedrooms","label":"Bedrooms","type":"number","required":false},{"name":"bathrooms","label":"Bathrooms","type":"number","required":false},{"name":"area_size","label":"Area / Size","type":"text","required":false},{"name":"year_built","label":"Year Built","type":"text","required":false},{"name":"description","label":"Property Description","type":"textarea","required":true,"default":"Presenting this attractive property offering generous accommodation in a sought-after location. Highlights include the features listed below. Early viewing is highly recommended."},{"name":"features","label":"Key Features & Amenities","type":"textarea","required":false,"default":"List the standout features and amenities — e.g. parking, garden, modern kitchen, security, proximity to schools and transport."},{"name":"agent_name","label":"Agent / Contact Name","type":"text","required":false},{"name":"agent_contact","label":"Agent Contact Details","type":"text","required":false}]}', faqs = '[{"q":"What makes an effective property listing sheet?","a":"An effective listing leads with a compelling title and a clear headline price, presents key facts (type, bedrooms, bathrooms, size, year), highlights standout features and location benefits, and gives clear agent contact details. A clean, professional layout builds buyer and tenant confidence."},{"q":"Can I use this listing for both sales and rentals?","a":"Yes. Choose the listing type (for sale, for rent or for lease) and the sheet adapts the price and presentation accordingly, so you can market residential or commercial property to buyers or tenants."},{"q":"Can I download this Property Listing Sheet as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Property Listing Sheet suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'property-listing-sheet-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"notice_date","label":"Date","type":"date","required":true},{"name":"landlord","label":"Landlord / Lessor","type":"party","required":true},{"name":"tenant","label":"Tenant / Lessee","type":"party","required":true},{"name":"property_address","label":"Property Address","type":"text","required":true},{"name":"current_lease_end","label":"Current Lease End Date","type":"date","required":true},{"name":"renewal_start","label":"Renewal Start Date","type":"date","required":true},{"name":"renewal_end","label":"Renewal End Date","type":"date","required":false},{"name":"new_rent","label":"Renewed Rent Amount","type":"number","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"body","label":"Notice Body","type":"textarea","required":false,"default":"We are writing in relation to your tenancy of the above property. We are pleased to offer to renew your lease on the terms set out below. If you wish to accept the renewal, please sign and return a copy of this notice by the response date indicated."},{"name":"response_by","label":"Please Respond By","type":"text","required":false},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"landlord_signature","label":"Landlord Signature","type":"signature","required":false},{"name":"tenant_signature","label":"Tenant Acceptance","type":"signature","required":false}]}', faqs = '[{"q":"What should a lease renewal notice include?","a":"It should identify the property and the current lease end date, state the proposed renewal start and end dates and any change in rent or terms, and give the tenant a clear date by which to respond. Serving renewal notices in good time and in the form required by local law avoids the tenancy lapsing unintentionally."},{"q":"How much notice is required to renew or change a lease?","a":"Notice periods are set by your lease and by local landlord-tenant law and vary widely. Serve the notice well before the current term ends and confirm the minimum period and any prescribed form required where the property is located."},{"q":"Can I download this Lease Renewal Notice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Lease Renewal Notice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'lease-renewal-notice-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"property_address","label":"Property Address","type":"text","required":true},{"name":"inspection_type","label":"Inspection Type","type":"select","required":false,"options":["Move-In","Move-Out","Routine / Periodic","Pre-Purchase"],"default":"Routine / Periodic"},{"name":"inspection_date","label":"Inspection Date","type":"date","required":true},{"name":"inspector_name","label":"Inspector / Agent Name","type":"text","required":true},{"name":"landlord","label":"Landlord / Owner","type":"party","required":false},{"name":"tenant","label":"Tenant","type":"party","required":false},{"name":"room_conditions","label":"Room-by-Room Condition","type":"line_items","required":true},{"name":"overall_condition","label":"Overall Condition Summary","type":"textarea","required":false,"default":"The overall condition of the property at the time of inspection is summarised here, noting cleanliness, state of repair and any items requiring attention."},{"name":"issues_found","label":"Issues / Defects Identified","type":"textarea","required":false,"default":"Any defects, damage or maintenance issues identified during the inspection are recorded below, with the responsible party and recommended action."},{"name":"inspector_signature","label":"Inspector Signature","type":"signature","required":false},{"name":"tenant_signature","label":"Tenant Acknowledgement","type":"signature","required":false}]}', faqs = '[{"q":"Why is a property inspection (condition) report important?","a":"A dated, signed condition report — ideally at move-in and move-out — provides objective evidence of the property''s state and is the single most effective protection against deposit disputes. It records the condition of each room and any existing damage so responsibility is clear."},{"q":"Should the tenant sign the inspection report?","a":"Yes, wherever possible. The tenant''s signature confirms they agree with the recorded condition at move-in or move-out, which makes the report far more reliable if a disagreement over damage or the deposit arises later."},{"q":"Can I download this Property Inspection Report as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Property Inspection Report suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'property-inspection-report-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"reference_number","label":"Reference Number","type":"text","required":false},{"name":"notice_date","label":"Date","type":"date","required":true},{"name":"landlord","label":"Landlord / Lessor","type":"party","required":true},{"name":"tenant","label":"Tenant / Lessee","type":"party","required":true},{"name":"property_address","label":"Property Address","type":"text","required":true},{"name":"reason","label":"Reason for Notice","type":"select","required":false,"options":["Non-Payment of Rent","Breach of Lease Terms","End of Tenancy / No-Fault","Other"],"default":"Non-Payment of Rent"},{"name":"grounds","label":"Grounds / Details","type":"textarea","required":true,"default":"This notice is served on the grounds described below. The tenant is required to remedy the breach (where capable of remedy) or to vacate the premises by the date specified."},{"name":"vacate_by","label":"Vacate / Remedy By Date","type":"date","required":true},{"name":"amount_owed","label":"Amount Owed (if applicable)","type":"number","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"body","label":"Notice Body","type":"textarea","required":false,"default":"This is a formal notice in relation to your tenancy of the above property. Please read it carefully and take it seriously. If you do not comply by the date stated, the landlord may take further action, including applying to the court for possession, in accordance with applicable law."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"landlord_signature","label":"Landlord Signature","type":"signature","required":false}]}', faqs = '[{"q":"Is an eviction notice enough to remove a tenant?","a":"No. An eviction (or possession) notice is the required first step that formally notifies the tenant of the grounds and the date to remedy or vacate — but a landlord generally cannot physically remove a tenant without following the legal process, which usually requires a court order. Self-help eviction is unlawful in most jurisdictions."},{"q":"What must a valid eviction notice contain?","a":"It must correctly identify the parties and property, state the legal grounds, give the notice period and form required by local law, and specify the date to remedy or vacate. Because the rules and minimum notice periods are strictly local, confirm them for where the property is located — defective notices are frequently struck out."},{"q":"Can I download this Eviction Notice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Eviction Notice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'eviction-notice-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"receipt_number","label":"Receipt No.","type":"text","required":true},{"name":"payment_date","label":"Payment Date","type":"date","required":true},{"name":"landlord","label":"Received By (Landlord / Agent)","type":"party","required":true},{"name":"tenant","label":"Received From (Tenant)","type":"party","required":true},{"name":"property_address","label":"Property Address","type":"text","required":true},{"name":"amount_paid","label":"Amount Paid","type":"number","required":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"rent_period","label":"Rent Period Covered","type":"text","required":true},{"name":"payment_method","label":"Payment Method","type":"select","required":false,"options":["Cash","Bank Transfer","Cheque","Card","Online"],"default":"Bank Transfer"},{"name":"balance_due","label":"Outstanding Balance","type":"number","required":false},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"This receipt acknowledges payment of rent for the period stated for the above property. Please retain it for your records."},{"name":"landlord_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"Why should landlords issue rent receipts?","a":"A rent receipt is formal proof that rent was paid for a specific period. It protects both parties in any dispute over arrears, is often needed by tenants for benefit claims, tax or visa purposes, and in some jurisdictions must be provided on request. It should show the amount, period, property and payment method."},{"q":"What details must a valid rent receipt include?","a":"It should include a receipt number, the payment date, the landlord and tenant, the property, the amount paid and the rent period it covers, the payment method, and any outstanding balance — signed or acknowledged by the landlord or agent."},{"q":"Can I download this Rent Receipt as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Rent Receipt suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'rent-receipt-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"property_address","label":"Property Applied For","type":"text","required":true},{"name":"application_date","label":"Application Date","type":"date","required":true},{"name":"applicant","label":"Applicant Details","type":"party","required":true},{"name":"date_of_birth","label":"Date of Birth","type":"date","required":false},{"name":"current_address","label":"Current Address","type":"text","required":false},{"name":"employment_status","label":"Employment Status","type":"text","required":false},{"name":"employer_name","label":"Employer / Income Source","type":"text","required":false},{"name":"monthly_income","label":"Monthly Income","type":"number","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"desired_move_in","label":"Desired Move-In Date","type":"date","required":false},{"name":"occupants","label":"Number of Occupants","type":"number","required":false},{"name":"references","label":"References (Previous Landlord / Employer)","type":"textarea","required":false,"default":"Please provide contact details for a previous landlord and/or your employer who can act as references."},{"name":"consent","label":"Declaration & Consent","type":"textarea","required":false,"default":"I declare that the information provided is true and complete. I consent to the landlord or agent verifying this information and conducting reference and (where lawful) credit and background checks for the purpose of assessing this application, in accordance with applicable data-protection law."},{"name":"applicant_signature","label":"Applicant Signature","type":"signature","required":false}]}', faqs = '[{"q":"What information should a rental application collect?","a":"A thorough application collects the applicant''s identity and contact details, current address, employment and income, desired move-in date, number of occupants, and references — together with the applicant''s signed consent to verification and background checks. This helps landlords assess suitability fairly and consistently."},{"q":"Do I need consent to run tenant background or credit checks?","a":"Yes. Under data-protection laws such as the GDPR (EU/UK) and various US state laws, you should collect the applicant''s informed, written consent before running credit, reference or background checks, and only use the data for assessing the application. The template includes a declaration-and-consent section for this purpose."},{"q":"Can I download this Tenant Application Form as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Tenant Application Form suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'tenant-application-form-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"property_address","label":"Property Address","type":"text","required":true},{"name":"checklist_type","label":"Checklist Type","type":"select","required":false,"options":["Move-In","Move-Out"],"default":"Move-In"},{"name":"checklist_date","label":"Date","type":"date","required":true},{"name":"landlord","label":"Landlord / Agent","type":"party","required":false},{"name":"tenant","label":"Tenant","type":"party","required":false},{"name":"items","label":"Room & Item Condition","type":"line_items","required":true},{"name":"meter_readings","label":"Utility Meter Readings","type":"textarea","required":false,"default":"Record the gas, electricity and water meter readings at the date of this checklist so consumption can be correctly allocated."},{"name":"notes","label":"Additional Notes","type":"textarea","required":false,"default":"Record any existing damage, missing items or other observations. Photographs taken on this date are attached and form part of this record."},{"name":"landlord_signature","label":"Landlord / Agent Signature","type":"signature","required":false},{"name":"tenant_signature","label":"Tenant Signature","type":"signature","required":false}]}', faqs = '[{"q":"Why complete a move-in and move-out checklist?","a":"Completing a detailed, signed checklist at both move-in and move-out — ideally with dated photographs and meter readings — provides clear evidence of the property''s condition at the start and end of the tenancy. This is the most effective way to resolve deposit and damage disputes fairly."},{"q":"Should the checklist include meter readings?","a":"Yes. Recording gas, electricity and water meter readings at move-in and move-out ensures utility consumption is correctly allocated and avoids disputes over bills relating to periods before or after the tenancy."},{"q":"Can I download this Move-In / Move-Out Checklist as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Move-In / Move-Out Checklist suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'move-in-move-out-checklist-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"property_address","label":"Property Address","type":"text","required":true},{"name":"disclosure_date","label":"Date","type":"date","required":true},{"name":"seller","label":"Seller / Owner","type":"party","required":true},{"name":"buyer","label":"Prospective Buyer","type":"party","required":false},{"name":"property_condition","label":"Known Condition & Defects","type":"textarea","required":true,"default":"The seller discloses the following known material facts and defects affecting the property. This disclosure is made to the best of the seller''s knowledge and is not a warranty or a substitute for the buyer''s own inspection."},{"name":"structural_systems","label":"Structure, Systems & Services","type":"textarea","required":false,"default":"Disclose the known condition of the structure, roof, foundations, electrical, plumbing, heating/cooling and any past significant repairs."},{"name":"environmental_hazards","label":"Environmental & Hazard Disclosures","type":"textarea","required":false,"default":"Disclose any known environmental hazards (e.g. damp, asbestos, lead paint, radon, flooding history, pests) affecting the property, as required by applicable law."},{"name":"legal_matters","label":"Legal / Boundary / Title Matters","type":"textarea","required":false,"default":"Disclose any known disputes, easements, encroachments, planning or permit issues, or other legal matters affecting the property."},{"name":"declaration","label":"Seller''s Declaration","type":"textarea","required":false,"default":"The seller declares that the information provided is accurate and complete to the best of their knowledge as of the date of this disclosure."},{"name":"seller_signature","label":"Seller Signature","type":"signature","required":false},{"name":"buyer_signature","label":"Buyer Acknowledgement","type":"signature","required":false}]}', faqs = '[{"q":"What is a real estate disclosure form and is it required?","a":"A property disclosure form is the seller''s statement of known material facts and defects affecting a property. In many US states and other jurisdictions some form of disclosure is legally required, and even where it is not, accurate disclosure protects the seller against later misrepresentation claims. It is not a substitute for the buyer''s own survey or inspection."},{"q":"What should sellers disclose?","a":"Sellers should disclose known material defects in the structure and systems, environmental hazards (such as damp, asbestos, lead, radon or flooding history), and legal matters such as boundary disputes, easements or planning issues. When in doubt, disclose — non-disclosure of known defects is a common source of post-sale litigation."},{"q":"Can I download this Real Estate Disclosure Form as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Real Estate Disclosure Form suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'real-estate-disclosure-form-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Your Company / Name","type":"text","required":true},{"name":"proposal_title","label":"Proposal Title","type":"text","required":true,"default":"Business Proposal"},{"name":"proposal_number","label":"Proposal No.","type":"text","required":false},{"name":"proposal_date","label":"Date","type":"date","required":true},{"name":"client","label":"Prepared For (Client)","type":"party","required":true},{"name":"executive_summary","label":"Executive Summary","type":"textarea","required":false,"default":"This proposal sets out how we will help you achieve your objectives, our recommended approach, the deliverables, the investment required and the next steps. We are confident we can deliver real value and look forward to working with you."},{"name":"problem_statement","label":"Understanding of Your Needs","type":"textarea","required":false,"default":"We understand that you are seeking to address the challenges and goals described here. Our proposal is shaped around delivering measurable outcomes against these needs."},{"name":"proposed_solution","label":"Proposed Solution & Approach","type":"textarea","required":true,"default":"We propose the solution and approach described below, structured to deliver the agreed objectives efficiently and to a high professional standard."},{"name":"pricing","label":"Investment / Pricing","type":"line_items","required":true,"has_unit":true,"per_item_tax":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"timeline","label":"Timeline","type":"text","required":false},{"name":"terms","label":"Terms & Validity","type":"textarea","required":false,"default":"This proposal is valid for the period stated. On acceptance, a separate agreement or statement of work will set out the binding terms. Pricing assumes the scope described; changes will be agreed in writing."},{"name":"valid_until","label":"Valid Until","type":"date","required":false},{"name":"prepared_signature","label":"Authorized Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a winning business proposal include?","a":"A strong proposal opens with an executive summary, demonstrates a clear understanding of the client''s needs, presents a specific solution and approach, sets out transparent pricing and a timeline, and ends with clear terms and a call to action. Personalising it to the client materially increases win rates."},{"q":"How is a proposal different from a contract?","a":"A proposal persuades and sets out what you recommend and what it will cost; a contract (or statement of work) is the binding agreement signed once the client accepts. It is good practice to follow an accepted proposal with a signed agreement that captures the detailed terms."},{"q":"Can I download this Business Proposal as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Business Proposal suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'business-proposal-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"client","label":"Client","type":"party","required":false},{"name":"brief_date","label":"Date","type":"date","required":true},{"name":"background","label":"Background & Context","type":"textarea","required":false,"default":"This brief sets out the background, objectives and requirements for the project so that everyone involved shares a clear, common understanding before work begins."},{"name":"objectives","label":"Objectives & Goals","type":"textarea","required":true,"default":"The project aims to achieve the specific, measurable objectives described below."},{"name":"target_audience","label":"Target Audience","type":"textarea","required":false,"default":"Describe the primary audience or end users the project is intended to serve."},{"name":"scope_deliverables","label":"Scope & Deliverables","type":"textarea","required":true,"default":"The project will deliver the items listed here. Anything not listed is out of scope and will be handled as a separate request."},{"name":"requirements","label":"Requirements & Constraints","type":"textarea","required":false,"default":"Note any technical, brand, budget or regulatory requirements and constraints that the work must respect."},{"name":"budget","label":"Budget","type":"text","required":false},{"name":"timeline","label":"Timeline / Key Dates","type":"text","required":false},{"name":"approved_by","label":"Approved By","type":"text","required":false}]}', faqs = '[{"q":"What is the purpose of a project brief?","a":"A project brief aligns everyone on the objectives, audience, scope, deliverables, constraints, budget and timeline before work starts. A clear brief prevents misunderstandings and scope creep and is the reference point against which the finished work is judged."},{"q":"How detailed should a project brief be?","a":"Detailed enough that someone unfamiliar with the project could understand what success looks like and what is in and out of scope, but concise enough to be read and agreed quickly. Explicitly listing what is out of scope is one of the most valuable parts of a good brief."},{"q":"Can I download this Project Brief as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Project Brief suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'project-brief-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"sow_number","label":"SOW No.","type":"text","required":false},{"name":"sow_date","label":"Date","type":"date","required":true},{"name":"client","label":"Client","type":"party","required":true},{"name":"service_provider","label":"Service Provider","type":"party","required":true},{"name":"overview","label":"Project Overview","type":"textarea","required":false,"default":"This Statement of Work describes the services, deliverables, timeline and acceptance criteria for the project. It forms part of, and is governed by, the parties'' underlying agreement."},{"name":"scope_of_services","label":"Scope of Services","type":"textarea","required":true,"default":"The service provider shall perform the services described below. Services not expressly listed are excluded and, if required, will be agreed as a separate change to this Statement of Work."},{"name":"deliverables","label":"Deliverables & Milestones","type":"line_items","required":true},{"name":"acceptance_criteria","label":"Acceptance Criteria","type":"textarea","required":false,"default":"Each deliverable will be deemed accepted when it meets the criteria described here, or after the agreed review period if no reasoned objection is raised."},{"name":"timeline","label":"Timeline / Key Dates","type":"text","required":false},{"name":"fees","label":"Fees","type":"number","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"assumptions","label":"Assumptions & Dependencies","type":"textarea","required":false,"default":"This Statement of Work assumes timely client input and the dependencies noted. Delays in dependencies may affect the timeline and fees."},{"name":"provider_signature","label":"Service Provider Signature","type":"signature","required":false},{"name":"client_signature","label":"Client Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is a Statement of Work (SOW) and why use one?","a":"A Statement of Work defines exactly what services and deliverables will be provided, by when, to what acceptance criteria, and for what fee — usually under a broader master agreement. It is the single most effective tool for preventing scope creep and payment disputes on a project."},{"q":"What should a good scope of work include?","a":"Clear in-scope services and explicit exclusions, specific deliverables and milestones, acceptance criteria, the timeline, fees, and the assumptions and client dependencies the work relies on. Defining acceptance criteria up front avoids arguments about whether work is ''done''."},{"q":"Can I download this Scope of Work / Statement of Work as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Scope of Work / Statement of Work suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'scope-of-work-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"invoice_number","label":"Invoice No.","type":"text","required":true},{"name":"issue_date","label":"Issue Date","type":"date","required":true},{"name":"due_date","label":"Due Date","type":"date","required":false},{"name":"freelancer","label":"From (Freelancer)","type":"party","required":true},{"name":"client","label":"Bill To (Client)","type":"party","required":true},{"name":"project_reference","label":"Project / PO Reference","type":"text","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"items","label":"Services / Items","type":"line_items","required":true,"has_unit":true,"per_item_tax":true},{"name":"tax_rate","label":"Tax Rate (%)","type":"number","required":false},{"name":"discount_value","label":"Discount","type":"number","required":false},{"name":"payment_terms","label":"Payment Terms","type":"textarea","required":false,"default":"Payment is due by the date shown. Please make payment to the bank details provided. Late payments may incur interest at the statutory or agreed rate."},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"Thank you for your business. Please quote the invoice number with your payment."}]}', faqs = '[{"q":"What should a freelancer''s invoice include to get paid on time?","a":"Include a unique invoice number, the issue and due dates, your and the client''s details, a clear breakdown of services with rates, any tax, your payment terms and bank/payment details, and the project reference. Clear due dates and payment terms measurably reduce late payment."},{"q":"Should freelancers charge tax on invoices?","a":"It depends on where you and your client are based and whether you are registered for VAT/GST/sales tax. The template lets you add a tax rate and shows your tax number from your profile. If you are unsure of your obligations for cross-border work, check with a local tax adviser."},{"q":"Can I download this Freelance Invoice as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Freelance Invoice suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'freelance-invoice-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Your Company","type":"text","required":false},{"name":"form_title","label":"Form Title","type":"text","required":true,"default":"Client Onboarding Form"},{"name":"onboarding_date","label":"Date","type":"date","required":true},{"name":"client","label":"Client Details","type":"party","required":true},{"name":"primary_contact","label":"Primary Contact & Role","type":"text","required":false},{"name":"billing_contact","label":"Billing Contact","type":"text","required":false},{"name":"preferred_communication","label":"Preferred Communication Channel","type":"text","required":false},{"name":"project_goals","label":"Project Goals & Expectations","type":"textarea","required":false,"default":"Tell us about your goals, what success looks like, and any expectations or concerns so we can tailor our service to you."},{"name":"brand_assets","label":"Brand Assets & Access","type":"textarea","required":false,"default":"List the brand assets, logins, accounts or materials you will provide, and how you will share them securely."},{"name":"budget_range","label":"Budget Range","type":"text","required":false},{"name":"timeline","label":"Desired Timeline","type":"text","required":false},{"name":"additional_info","label":"Anything Else We Should Know","type":"textarea","required":false},{"name":"client_signature","label":"Client Signature","type":"signature","required":false}]}', faqs = '[{"q":"Why use a client onboarding form?","a":"A structured onboarding form captures everything you need to start work smoothly — goals, key contacts, brand assets and access, budget, timeline and expectations — in one place. It creates a professional first impression and prevents the back-and-forth that delays project kick-off."},{"q":"What should I collect during client onboarding?","a":"Collect the client''s company and contact details, billing contact, project goals and success criteria, brand assets and secure ac