UPDATE document_templates SET fields_schema = '{"fields":[{"name":"letter_date","label":"Date","type":"date","required":true},{"name":"sender","label":"Your Details","type":"party","required":true},{"name":"recipient","label":"Addressed To","type":"party","required":false},{"name":"subject","label":"Subject / Role","type":"text","required":true},{"name":"body","label":"Letter Body","type":"textarea","required":true,"default":"I am writing to introduce myself and share my portfolio for your consideration. With a strong track record in my field, I help clients achieve outstanding results through creativity, professionalism and reliability. The attached portfolio showcases selected work that demonstrates the quality and range of what I can deliver. I would welcome the opportunity to discuss how I can contribute to your project."},{"name":"highlights","label":"Key Highlights / Selected Work","type":"textarea","required":false,"default":"Summarise two or three standout projects or achievements most relevant to the reader, with the results you delivered."},{"name":"portfolio_link","label":"Portfolio Link","type":"text","required":false},{"name":"closing","label":"Closing","type":"text","required":false,"default":"Kind regards,"},{"name":"sender_signature","label":"Signature","type":"signature","required":false}]}', faqs = '[{"q":"What makes a strong portfolio cover letter?","a":"A strong cover letter is concise and tailored: it introduces you, connects your strongest, most relevant work to the reader''s needs, quantifies results, and invites a conversation. Lead with the value you deliver rather than a list of tasks, and always link to your portfolio."},{"q":"How long should a portfolio cover letter be?","a":"Keep it to a single page — three or four short paragraphs. Its job is to earn a click to your portfolio and a reply, not to tell your whole story, so prioritise the highlights most relevant to the specific reader or role."},{"q":"Can I download this Portfolio Cover Letter as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Portfolio Cover Letter suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'portfolio-cover-letter-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"freelancer_name","label":"Freelancer / Employee Name","type":"text","required":true},{"name":"client","label":"Client / Project Owner","type":"party","required":false},{"name":"project_name","label":"Project Name","type":"text","required":true},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":true},{"name":"time_entries","label":"Time Entries","type":"line_items","required":true},{"name":"hourly_rate","label":"Hourly Rate","type":"number","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"This timesheet records billable and non-billable hours for the period stated. Hours are recorded accurately and in good faith and form the basis of any associated invoice."},{"name":"freelancer_signature","label":"Freelancer Signature","type":"signature","required":false},{"name":"client_signature","label":"Client Approval","type":"signature","required":false}]}', faqs = '[{"q":"Why keep a time-tracking sheet as a freelancer?","a":"A clear timesheet records the hours worked per task and day, justifies your invoices, and builds client trust through transparency. Approved timesheets are strong evidence if a client ever queries billable hours, and they also help you estimate future projects more accurately."},{"q":"Can I link a timesheet to my invoice?","a":"Yes. Record your hours and hourly rate here, have the client approve the period, and carry the totals into a matching freelance invoice. Attaching the approved timesheet to the invoice reduces payment queries."},{"q":"Can I download this Time Tracking Sheet as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Time Tracking Sheet suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'time-tracking-sheet-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"freelancer_name","label":"Your Name / Studio","type":"text","required":true},{"name":"proposal_title","label":"Proposal Title","type":"text","required":true,"default":"Project Proposal"},{"name":"proposal_date","label":"Date","type":"date","required":true},{"name":"client","label":"Prepared For (Client)","type":"party","required":true},{"name":"introduction","label":"Introduction","type":"textarea","required":false,"default":"Thank you for the opportunity to propose on your project. This proposal outlines my understanding of your needs, my recommended approach, deliverables, pricing and timeline. I am committed to delivering high-quality work and a smooth, professional experience."},{"name":"understanding","label":"Understanding of the Project","type":"textarea","required":true,"default":"Based on our discussions, I understand that you need the outcomes described here. My approach is shaped around delivering exactly that."},{"name":"approach","label":"Proposed Approach & Deliverables","type":"textarea","required":true,"default":"I will deliver the work in the stages and deliverables described below, keeping you informed at each milestone."},{"name":"pricing","label":"Pricing","type":"line_items","required":true,"has_unit":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"timeline","label":"Timeline","type":"text","required":false},{"name":"terms","label":"Terms","type":"textarea","required":false,"default":"This proposal is valid for the period stated. A deposit may be required to secure the booking, with the balance due as set out. On acceptance, a short agreement or statement of work will confirm the binding terms."},{"name":"valid_until","label":"Valid Until","type":"date","required":false},{"name":"freelancer_signature","label":"Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a freelance project proposal include?","a":"A persuasive freelance proposal shows you understand the client''s needs, sets out your approach and deliverables, gives clear pricing and a timeline, and states professional terms such as deposit, validity and what happens on acceptance. A confident, well-structured proposal wins more work and sets expectations early."},{"q":"Should I take a deposit before starting freelance work?","a":"Taking a deposit (commonly 30–50%) before starting is standard professional practice that protects your time and signals client commitment. State your deposit and payment schedule in the proposal so there are no surprises, and confirm them in the agreement or statement of work."},{"q":"Can I download this Freelance Proposal as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Freelance Proposal suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'freelance-proposal-template-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"sop_title","label":"SOP Title","type":"text","required":true,"default":"Standard Operating Procedure"},{"name":"sop_number","label":"SOP Number","type":"text","required":false},{"name":"version","label":"Version","type":"text","required":false,"default":"1.0"},{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"department","label":"Department / Process Owner","type":"text","required":false},{"name":"purpose","label":"Purpose","type":"textarea","required":true,"default":"This Standard Operating Procedure defines the standard, repeatable steps for carrying out the process described, to ensure consistency, quality, safety and compliance across the organisation."},{"name":"scope","label":"Scope","type":"textarea","required":false,"default":"This procedure applies to the roles, departments and activities described here. Exceptions, if any, are noted."},{"name":"responsibilities","label":"Roles & Responsibilities","type":"textarea","required":false,"default":"The roles responsible for performing, reviewing and approving each part of this procedure are defined here."},{"name":"procedure_steps","label":"Procedure Steps","type":"line_items","required":true},{"name":"references","label":"References & Related Documents","type":"textarea","required":false,"default":"List any policies, forms, standards or related SOPs referenced by this procedure."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"approved_signature","label":"Approval Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a standard operating procedure (SOP) contain?","a":"A good SOP states its purpose and scope, defines roles and responsibilities, lays out the steps in clear sequence, references related documents, and carries a version number, effective date and approval. This structure makes processes repeatable, auditable and easy to train against — and is expected under quality standards such as ISO 9001."},{"q":"Why version-control SOPs?","a":"Processes change, and everyone must follow the current version. A version number, effective date and approval record ensure people use the right procedure, support audits, and create a history of how a process has evolved."},{"q":"Can I download this Standard Operating Procedure (SOP) as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Standard Operating Procedure (SOP) suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'standard-operating-procedure-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"organization_name","label":"Organization","type":"text","required":true},{"name":"meeting_title","label":"Meeting Title","type":"text","required":true},{"name":"meeting_date","label":"Meeting Date","type":"date","required":true},{"name":"meeting_time","label":"Time","type":"text","required":false},{"name":"location","label":"Location / Platform","type":"text","required":false},{"name":"attendees","label":"Attendees","type":"textarea","required":true,"default":"List those present, any apologies for absence, and the chair and minute-taker."},{"name":"agenda_items","label":"Agenda Items & Discussion","type":"line_items","required":true},{"name":"action_items","label":"Action Items & Owners","type":"line_items","required":true},{"name":"decisions","label":"Decisions Made","type":"textarea","required":false,"default":"Record the key decisions reached, including any votes and outcomes."},{"name":"next_meeting","label":"Next Meeting Date","type":"date","required":false},{"name":"minutes_prepared_by","label":"Minutes Prepared By","type":"text","required":false},{"name":"chair_signature","label":"Chairperson Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should professional meeting minutes capture?","a":"Effective minutes record the date, attendees and apologies, the matters discussed under each agenda item, the decisions made, and — most importantly — the action items with named owners and due dates. They are a concise record of what was agreed, not a transcript of everything said."},{"q":"Are meeting minutes a legal record?","a":"For boards, committees and many companies, approved minutes are an official record that can have legal and governance significance, evidencing the decisions taken and the directors''/members'' diligence. They are usually reviewed and approved (and signed by the chair) at the following meeting."},{"q":"Can I download this Meeting Minutes as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Meeting Minutes suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'meeting-minutes-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"plan_title","label":"Plan Title","type":"text","required":true,"default":"Business Plan"},{"name":"plan_date","label":"Date","type":"date","required":true},{"name":"executive_summary","label":"Executive Summary","type":"textarea","required":true,"default":"This business plan summarises our company, the opportunity we are pursuing, our products and services, our market and competition, our strategy, our team and our financial projections. It is intended to guide our execution and to inform investors and partners."},{"name":"company_overview","label":"Company Overview","type":"textarea","required":false,"default":"Describe the company, its mission and vision, legal structure, location and current stage."},{"name":"products_services","label":"Products & Services","type":"textarea","required":false,"default":"Describe what you offer, the problem it solves, and your competitive advantage."},{"name":"market_analysis","label":"Market Analysis","type":"textarea","required":false,"default":"Describe your target market, its size and trends, your customers, and the competitive landscape."},{"name":"marketing_sales","label":"Marketing & Sales Strategy","type":"textarea","required":false,"default":"Explain how you will reach customers, your pricing, channels and sales approach."},{"name":"operations_team","label":"Operations & Management Team","type":"textarea","required":false,"default":"Describe how the business runs day to day and introduce the key people and their relevant experience."},{"name":"financial_plan","label":"Financial Plan & Projections","type":"textarea","required":false,"default":"Summarise your revenue model, key assumptions, funding requirements and financial projections."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false}]}', faqs = '[{"q":"What sections does a professional business plan need?","a":"A complete business plan includes an executive summary, company overview, products and services, market and competitor analysis, marketing and sales strategy, operations and management team, and a financial plan with projections. Investors and lenders internationally expect this structure, with the executive summary doing the heavy lifting."},{"q":"How long should a business plan be?","a":"Long enough to cover each section credibly but no longer — typically 15–30 pages plus financial appendices, with a one-to-two page executive summary that can stand alone. Clarity, realistic assumptions and evidence matter far more than length."},{"q":"Can I download this Business Plan as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Business Plan suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'business-plan-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Organization","type":"text","required":true},{"name":"memo_to","label":"To","type":"text","required":true},{"name":"memo_from","label":"From","type":"text","required":true},{"name":"memo_cc","label":"CC","type":"text","required":false},{"name":"memo_date","label":"Date","type":"date","required":true},{"name":"subject","label":"Subject","type":"text","required":true},{"name":"body","label":"Memo Body","type":"textarea","required":true,"default":"This memo is to inform you of the matter set out below. Please review it and take any action indicated. Should you have any questions, please contact the sender directly."},{"name":"action_required","label":"Action Required","type":"textarea","required":false,"default":"Clearly state any action recipients must take and by when."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_signature","label":"Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is the correct format for a business memo?","a":"A business memo uses a clear header — To, From, CC, Date and Subject — followed by a concise body that states the purpose, gives the necessary detail, and specifies any action required and deadline. Memos are for internal communication and should be brief, direct and professional."},{"q":"When should I use a memo instead of an email or letter?","a":"Use a memo for formal internal announcements, policy changes or records that may need to be filed or referenced later. Letters are generally for external recipients, while memos communicate clearly and on the record within an organisation."},{"q":"Can I download this Memo as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Memo suitable for use in the US, 