UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"policy_title","label":"Policy Title","type":"text","required":true},{"name":"policy_number","label":"Policy Number","type":"text","required":false},{"name":"version","label":"Version","type":"text","required":false,"default":"1.0"},{"name":"effective_date","label":"Effective Date","type":"date","required":true},{"name":"policy_owner","label":"Policy Owner / Department","type":"text","required":false},{"name":"purpose","label":"Purpose","type":"textarea","required":true,"default":"This policy sets out the company''s position and requirements on the matter described, to ensure consistent, compliant and responsible conduct across the organisation."},{"name":"scope","label":"Scope","type":"textarea","required":false,"default":"This policy applies to the people, roles and activities described here."},{"name":"policy_statement","label":"Policy Statement","type":"textarea","required":true,"default":"The company''s policy is as set out below. All those within scope are required to understand and comply with it."},{"name":"responsibilities","label":"Responsibilities","type":"textarea","required":false,"default":"Define who is responsible for implementing, monitoring and enforcing this policy."},{"name":"compliance","label":"Compliance & Consequences","type":"textarea","required":false,"default":"Explain how compliance is monitored and the consequences of non-compliance, in line with company procedures and applicable law."},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"approved_signature","label":"Approval Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a company policy document include?","a":"A clear policy states its purpose and scope, the policy statement itself, the responsibilities for implementing and enforcing it, and the consequences of non-compliance — all version-controlled with an effective date and approval. This structure works for HR, IT, health-and-safety, data-protection and other corporate policies."},{"q":"How should policies be approved and communicated?","a":"Policies should be approved by an appropriate authority, given a version number and effective date, communicated to everyone within scope, and reviewed periodically. Keeping a record that staff have read and understood key policies supports compliance and helps defend against disputes."},{"q":"Can I download this Policy Document as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Policy Document suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'policy-document-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"list_title","label":"List Title","type":"text","required":true,"default":"Inventory List"},{"name":"inventory_date","label":"Date","type":"date","required":true},{"name":"location","label":"Location / Warehouse","type":"text","required":false},{"name":"prepared_by","label":"Prepared By","type":"text","required":false},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"inventory_items","label":"Inventory Items","type":"line_items","required":true,"has_unit":true},{"name":"notes","label":"Notes","type":"textarea","required":false,"default":"This inventory records the items, quantities and values held at the location and date stated. Quantities have been physically verified against records where indicated."},{"name":"verified_by","label":"Verified By","type":"text","required":false},{"name":"verified_signature","label":"Verification Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should an inventory list record?","a":"An inventory list records each item with its code/description, quantity on hand, unit value and total value, plus the location and date. Accurate inventory records underpin reliable accounts, efficient reordering, and audit and insurance requirements."},{"q":"Why perform and document physical inventory counts?","a":"Periodic physical counts reconcile what is actually on hand against your records, surfacing shrinkage, damage or errors. A dated, signed inventory record supports your financial statements and is frequently required by auditors and insurers."},{"q":"Can I download this Inventory List as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Inventory List suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'inventory-list-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"organization_name","label":"Organization","type":"text","required":true},{"name":"assessment_title","label":"Assessment Title","type":"text","required":true,"default":"Risk Assessment"},{"name":"activity_assessed","label":"Activity / Area Assessed","type":"text","required":true},{"name":"assessment_date","label":"Date","type":"date","required":true},{"name":"assessor_name","label":"Assessor Name","type":"text","required":true},{"name":"scope","label":"Scope & Context","type":"textarea","required":false,"default":"This assessment identifies the hazards/risks associated with the activity or area described, evaluates their likelihood and impact, and sets out the controls required to reduce them to an acceptable level."},{"name":"risk_items","label":"Identified Risks (Likelihood / Impact / Controls)","type":"line_items","required":true},{"name":"control_measures","label":"Control Measures & Actions","type":"textarea","required":false,"default":"Summarise the controls and actions required, who is responsible, and by when, to bring each risk to an acceptable level."},{"name":"review_date","label":"Review Date","type":"date","required":false},{"name":"approved_by","label":"Approved By","type":"text","required":false},{"name":"assessor_signature","label":"Assessor Signature","type":"signature","required":false}]}', faqs = '[{"q":"What is the standard approach to a risk assessment?","a":"The internationally recognised approach is to identify the hazards or risks, evaluate each by likelihood and impact, decide and implement control measures to reduce them to an acceptable level, assign owners and timescales, and review periodically. Documenting this is a legal requirement for workplace health and safety in many jurisdictions."},{"q":"How often should a risk assessment be reviewed?","a":"Review whenever circumstances change — new activities, equipment, incidents or regulations — and at planned intervals (commonly annually). Recording a review date and keeping previous versions evidences that risk is being actively managed."},{"q":"Can I download this Risk Assessment as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Risk Assessment suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'risk-assessment-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"organization_name","label":"Organization","type":"text","required":true},{"name":"report_title","label":"Report Title","type":"text","required":true,"default":"Internal Audit Report"},{"name":"audit_area","label":"Area / Process Audited","type":"text","required":true},{"name":"audit_period_from","label":"Audit Period From","type":"date","required":false},{"name":"audit_period_to","label":"Audit Period To","type":"date","required":false},{"name":"report_date","label":"Report Date","type":"date","required":true},{"name":"auditor_name","label":"Auditor Name","type":"text","required":true},{"name":"objectives_scope","label":"Objectives & Scope","type":"textarea","required":false,"default":"This audit was carried out to provide independent assurance over the area described, assessing the adequacy and effectiveness of controls against the relevant policies, standards and risks."},{"name":"findings","label":"Findings & Observations","type":"line_items","required":true},{"name":"recommendations","label":"Recommendations","type":"textarea","required":false,"default":"For each finding, a recommendation and a recommended priority are provided, together with the management response and the owner and target date for the agreed action."},{"name":"overall_opinion","label":"Overall Audit Opinion","type":"select","required":false,"options":["Satisfactory","Generally Satisfactory","Needs Improvement","Unsatisfactory"],"default":"Generally Satisfactory"},{"name":"approved_by","label":"Reviewed / Approved By","type":"text","required":false},{"name":"auditor_signature","label":"Auditor Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should an internal audit report contain?","a":"A professional audit report sets out the objectives and scope, the findings and observations (with evidence and risk rating), clear recommendations, management''s response with owners and dates, and an overall opinion. This structure aligns with internationally recognised internal-audit standards (such as those of the IIA)."},{"q":"How should audit findings be prioritised?","a":"Rate each finding by risk (for example high/medium/low) based on its likelihood and potential impact, so management can focus on what matters most. Agreeing an owner and target date for each recommended action turns the report into measurable improvement."},{"q":"Can I download this Internal Audit Report as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Internal Audit Report suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'internal-audit-report-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company Name","type":"text","required":true},{"name":"tagline","label":"Tagline / Slogan","type":"text","required":false},{"name":"address","label":"Address","type":"text","required":false},{"name":"phone","label":"Phone","type":"text","required":false},{"name":"email","label":"Email","type":"text","required":false},{"name":"website","label":"Website","type":"text","required":false},{"name":"registration_number","label":"Company Registration No.","type":"text","required":false},{"name":"tax_number","label":"Tax / VAT Number","type":"text","required":false},{"name":"body","label":"Letter Body","type":"textarea","required":false,"default":"Compose your letter content here. This professionally branded letterhead applies your company identity automatically to the page."},{"name":"signatory_name","label":"Signatory Name","type":"text","required":false},{"name":"signatory_title","label":"Signatory Title","type":"text","required":false},{"name":"signatory_signature","label":"Signature","type":"signature","required":false}]}', faqs = '[{"q":"What should a professional letterhead include?","a":"A professional letterhead carries your company name and logo, a tagline if you use one, full contact details (address, phone, email, website) and — where required — your company registration and tax/VAT numbers. Consistent letterhead reinforces your brand and is often a legal requirement on formal company correspondence."},{"q":"Are company registration and VAT numbers required on letterhead?","a":"In several jurisdictions (for example the UK and parts of the EU) limited companies must show their registered name, number and registered office on business letters and order forms. Include your registration and tax/VAT numbers to stay compliant and to look credible to customers and suppliers."},{"q":"Can I download this Company Letterhead as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Company Letterhead suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'company-letterhead-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Brand","type":"text","required":true},{"name":"plan_title","label":"Plan Title","type":"text","required":true,"default":"Marketing Plan"},{"name":"period","label":"Plan Period","type":"text","required":false},{"name":"plan_date","label":"Date","type":"date","required":true},{"name":"executive_summary","label":"Executive Summary","type":"textarea","required":false,"default":"This marketing plan sets out our goals, target audience, positioning, strategy and budget for the period, together with how we will measure success."},{"name":"market_situation","label":"Market Situation & SWOT","type":"textarea","required":false,"default":"Summarise the current market, key trends, and the brand''s strengths, weaknesses, opportunities and threats."},{"name":"target_audience","label":"Target Audience & Positioning","type":"textarea","required":true,"default":"Define the target segments, their needs, and how the brand is positioned to serve them better than the alternatives."},{"name":"objectives","label":"Marketing Objectives","type":"textarea","required":true,"default":"State specific, measurable marketing objectives for the period (for example awareness, leads, conversion or retention targets)."},{"name":"strategy_channels","label":"Strategy & Channels","type":"textarea","required":false,"default":"Describe the strategy and the mix of channels (digital, content, social, paid, PR, events) you will use to reach the objectives."},{"name":"budget","label":"Budget & Activities","type":"line_items","required":true,"has_unit":true},{"name":"currency","label":"Currency","type":"text","required":false,"default":"USD"},{"name":"kpis","label":"KPIs & Measurement","type":"textarea","required":false,"default":"Define the key performance indicators and how and when results will be reviewed."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false}]}', faqs = '[{"q":"What should a marketing plan include?","a":"A solid marketing plan covers the market situation and SWOT, the target audience and positioning, specific measurable objectives, the strategy and channel mix, a budget tied to activities, and the KPIs used to measure success. Linking every activity to an objective and a metric is what separates a plan from a wish list."},{"q":"How is a marketing plan different from a marketing strategy?","a":"A strategy is the high-level approach — who you target and how you position and win; a plan turns that strategy into specific objectives, activities, budget, timeline and metrics. This template captures both, with the strategy framing the detailed plan."},{"q":"Can I download this Marketing Plan as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Marketing Plan suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'marketing-plan-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"company_name","label":"Company / Organization","type":"text","required":true},{"name":"headline","label":"Headline","type":"text","required":true},{"name":"subheadline","label":"Sub-headline","type":"text","required":false},{"name":"release_location","label":"Dateline (City, Country)","type":"text","required":false},{"name":"release_date","label":"Release Date","type":"date","required":true},{"name":"release_timing","label":"Release Timing","type":"select","required":false,"options":["FOR IMMEDIATE RELEASE","EMBARGOED UNTIL"],"default":"FOR IMMEDIATE RELEASE"},{"name":"body","label":"Body","type":"textarea","required":true,"default":"Lead paragraph: summarise the news — who, what, when, where and why it matters — in the first sentence. Follow with supporting detail, context and a representative quote. Keep it factual, newsworthy and concise."},{"name":"quote","label":"Spokesperson Quote","type":"textarea","required":false,"default":"Include a quote from a named spokesperson that adds insight or emotion, with their name and title."},{"name":"boilerplate","label":"About the Company (Boilerplate)","type":"textarea","required":false,"default":"A short standard paragraph about the company — what it does, who it serves and any notable facts — used at the end of every release."},{"name":"media_contact","label":"Media Contact (Name, Email, Phone)","type":"text","required":false}]}', faqs = '[{"q":"What is the correct structure for a press release?","a":"A professional press release leads with a release line (e.g. ''FOR IMMEDIATE RELEASE''), a strong headline and dateline, then an inverted-pyramid body: the key news in the first paragraph (who, what, when, where, why), supporting detail, a spokesperson quote, a company boilerplate, and media-contact details. Keep it factual and newsworthy — journalists ignore marketing fluff."},{"q":"How long should a press release be?","a":"Aim for one page (around 300–500 words). Put the most important, newsworthy information first so an editor can grasp the story immediately, and make it easy to quote directly. Include a clear media contact so journalists can follow up."},{"q":"Can I download this Press Release as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Press Release suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'press-release-generator';
UPDATE document_templates SET fields_schema = '{"fields":[{"name":"brand_name","label":"Brand / Account","type":"text","required":true},{"name":"calendar_title","label":"Calendar Title","type":"text","required":true,"default":"Social Media Content Calendar"},{"name":"period_from","label":"Period From","type":"date","required":true},{"name":"period_to","label":"Period To","type":"date","required":false},{"name":"goals","label":"Goals & Themes","type":"textarea","required":false,"default":"Summarise the objectives and content themes for this period (for example awareness, engagement, product launches or seasonal campaigns)."},{"name":"platforms","label":"Platforms","type":"text","required":false,"default":"e.g. Instagram, LinkedIn, X, Facebook, TikTok, YouTube"},{"name":"content_items","label":"Scheduled Posts (Date / Platform / Content)","type":"line_items","required":true},{"name":"hashtags_notes","label":"Hashtags & Notes","type":"textarea","required":false,"default":"List recurring hashtags, handles to tag, and any approval or asset notes."},{"name":"prepared_by","label":"Prepared By","type":"text","required":false}]}', faqs = '[{"q":"Why use a social media content calendar?","a":"A content calendar plans what you will post, when and on which platform, so your output is consistent, on-strategy and aligned to campaigns and key dates. It prevents last-minute scrambles, improves quality through planning, and makes it easy to coordinate approvals and assets across a team."},{"q":"What should each calendar entry include?","a":"Each entry should show the date and time, the platform, the content or caption, the asset or link required, any hashtags or tags, and the post''s status (draft, approved, scheduled, published). Tying posts to themes and goals keeps the calendar strategic rather than random."},{"q":"Can I download this Social Media Content Calendar as PDF and Word?","a":"Yes. Every document you create on Invoxaco can be exported as a polished, print-ready PDF, and Pro and Premium plans can also download a fully editable Microsoft Word (DOCX) file."},{"q":"Is this Social Media Content Calendar suitable for use in the US, UK, EU and other countries?","a":"The template uses clear, internationally accepted business language and a neutral structure that works across the United States, United Kingdom, European Union and most other jurisdictions. Set the governing law or jurisdiction field to your country, and for high-value or regulated matters have a local professional review the final document."},{"q":"Can I add my company logo, branding and signature?","a":"Yes. Add your logo, brand colour, authorised signature and company stamp once in your settings and they are applied automatically to this and every other document you generate."}]' WHERE slug = 'social-media-content-calendar-generator';
